// ─── REUSABLE BRANCH PICKER (premium multi-select for managed branches) ───
// ใช้กับ Area / Operation Manager ที่ต้องเลือกสาขาในขอบเขตการดูแล
// คืน HTML string. Call wireBranchPicker(rootEl) หลัง render เพื่อ attach search/select-all/clear
let _branchPickerSeq = 0;
function renderBranchPicker({ name, branches, selected = [], pickerId = null } = {}) {
  const id = pickerId || ('branch_pk_' + (++_branchPickerSeq));
  const sel = new Set((selected || []).filter(Boolean));
  if (!branches || !branches.length) {
    return `<div class="branch-picker" data-branch-picker><div class="branch-picker-empty">ไม่มีข้อมูลสาขาในระบบ</div></div>`;
  }
  const total = branches.length;
  const checked = branches.filter(b => sel.has(b.id)).length;
  return `
    <div class="branch-picker" data-branch-picker id="${id}">
      <div class="branch-picker-toolbar">
        <div class="branch-picker-search">
          <input type="search" placeholder="ค้นหารหัส หรือชื่อสาขา..." data-branch-search aria-label="ค้นหาสาขา"/>
        </div>
        <span class="branch-picker-count" data-branch-count>${checked} / ${total}</span>
        <div class="branch-picker-actions">
          <button type="button" data-branch-select-all>เลือกทั้งหมด</button>
          <button type="button" data-branch-clear>ล้าง</button>
        </div>
      </div>
      <div class="branch-picker-grid" data-branch-grid>
        ${branches.map(b => {
          // [UI] ทุก dropdown/picker สาขา แสดงเฉพาะรหัส (ไม่ใส่ชื่อแบรนด์)
          // เก็บ data-search ไว้เพื่อ search ตามชื่อก็ยังหาเจอ + title hover เห็นชื่อเต็มได้
          const searchKey = (b.id + ' ' + (b.name || '')).toLowerCase();
          return `
            <label class="branch-chip is-codeonly" data-branch-chip data-search="${escapeHtml(searchKey)}" title="${escapeHtml(b.name || '')}">
              <input type="checkbox" name="${escapeHtml(name)}" value="${escapeHtml(b.id)}" ${sel.has(b.id) ? 'checked' : ''}/>
              <span class="branch-chip-indicator" aria-hidden="true"></span>
              <span class="branch-chip-content">
                <span class="branch-chip-code">${escapeHtml(b.id)}</span>
              </span>
            </label>`;
        }).join('')}
      </div>
    </div>`;
}
function wireBranchPicker(root) {
  if (!root) return;
  const picker = root.matches?.('[data-branch-picker]') ? root : root.querySelector('[data-branch-picker]');
  if (!picker) return;
  const grid = picker.querySelector('[data-branch-grid]');
  const countEl = picker.querySelector('[data-branch-count]');
  const search = picker.querySelector('[data-branch-search]');
  const selectAllBtn = picker.querySelector('[data-branch-select-all]');
  const clearBtn = picker.querySelector('[data-branch-clear]');
  if (!grid) return;
  const chips = Array.from(grid.querySelectorAll('[data-branch-chip]'));
  const total = chips.length;
  const updateCount = () => {
    if (!countEl) return;
    const checked = chips.filter(c => c.querySelector('input[type="checkbox"]:checked')).length;
    countEl.textContent = `${checked} / ${total}`;
  };
  const applyFilter = () => {
    const q = (search?.value || '').trim().toLowerCase();
    chips.forEach(c => {
      const match = !q || (c.getAttribute('data-search') || '').includes(q);
      c.classList.toggle('is-hidden', !match);
    });
  };
  grid.addEventListener('change', (e) => {
    if (e.target.matches('input[type="checkbox"]')) updateCount();
  });
  if (search) search.addEventListener('input', applyFilter);
  if (selectAllBtn) selectAllBtn.addEventListener('click', () => {
    chips.forEach(c => {
      if (c.classList.contains('is-hidden')) return;
      const cb = c.querySelector('input[type="checkbox"]');
      if (cb && !cb.checked) cb.checked = true;
    });
    updateCount();
  });
  if (clearBtn) clearBtn.addEventListener('click', () => {
    chips.forEach(c => {
      if (c.classList.contains('is-hidden')) return;
      const cb = c.querySelector('input[type="checkbox"]');
      if (cb && cb.checked) cb.checked = false;
    });
    updateCount();
  });
}

// ─── REUSABLE EMPLOYEE PICKER (searchable input + datalist) ───
// ใช้แทน <select> ที่มีพนักงานเยอะ — พิมพ์ ชื่อ/นามสกุล/ชื่อเล่น/รหัส กรองได้
// คืน HTML string. Call wireEmployeePickers() หลัง render เพื่อ attach listeners
let _empPickerSeq = 0;
function employeePicker({ name, emps, selected = '', required = false, placeholder = 'พิมพ์ค้นหา ชื่อ / นามสกุล / ชื่อเล่น / รหัส', containerClass = '', inputId = null, disabled = false } = {}) {
  // inputId = hidden input id ที่ caller กำหนด (เพื่อให้ existing code ที่ reference เลข id เดิมยังใช้ได้)
  // ถ้าไม่กำหนด → auto-gen
  const id = inputId || ('emp_pk_' + (++_empPickerSeq));
  const dlId = id + '_dl';
  const empFormat = (e) => `${e.id} — ${(e.title || '') + (e.firstName || '')} ${e.lastName || ''}${e.nickname ? ' (' + e.nickname + ')' : ''}`;
  const selectedEmp = selected ? emps.find(e => e.id === selected) : null;
  const displayVal = selectedEmp ? empFormat(selectedEmp) : '';
  return `
    <input type="text"
           id="${id}_search"
           class="emp-picker-search ${containerClass}"
           data-picker="${id}"
           list="${dlId}"
           autocomplete="off"
           ${required ? 'required' : ''}
           ${disabled ? 'disabled' : ''}
           placeholder="${escapeHtml(placeholder)}"
           value="${escapeHtml(displayVal)}"/>
    <input type="hidden" name="${name}" id="${id}" value="${escapeHtml(selected)}"/>
    <datalist id="${dlId}">
      ${emps.map(e => `<option value="${escapeHtml(empFormat(e))}"></option>`).join('')}
    </datalist>
    <small class="muted-2" id="${id}_hint" style="font-size:11px"></small>
  `;
}

// Wire all employee pickers in a container (default: document)
// Optional onPick(emp, hiddenInput) callback fires when selection valid
function wireEmployeePickers(rootSelector, onPick) {
  const root = rootSelector ? document.querySelector(rootSelector) : document;
  if (!root) return;
  root.querySelectorAll('.emp-picker-search').forEach(input => {
    if (input.dataset.wired) return; // กัน wire ซ้ำ
    input.dataset.wired = '1';
    const pickerId = input.dataset.picker;
    const hidden = document.getElementById(pickerId);
    const hint = document.getElementById(pickerId + '_hint');
    const update = () => {
      const v = (input.value || '').trim();
      let emp = null;
      if (v) {
        // exact ID
        emp = DB.getEmployee(v);
        // "ID — name" format
        if (!emp && v.includes('—')) {
          const id = v.split(/\s*—\s*/)[0].trim();
          emp = DB.getEmployee(id);
        }
      }
      if (emp) {
        hidden.value = emp.id;
        if (hint) hint.innerHTML = `<span style="color:var(--success)">✓ ${escapeHtml(emp.firstName + ' ' + (emp.lastName || ''))}</span>`;
        if (onPick) onPick(emp, hidden);
      } else {
        hidden.value = '';
        if (hint) hint.innerHTML = v ? '<span style="color:var(--danger)">ไม่พบพนักงาน</span>' : '';
      }
    };
    input.addEventListener('input', update);
    input.addEventListener('change', update);
  });
}

