function matchUniformItemFromStock(parsed, masterItems) {
  if (!parsed.parseable) return null;
  // ลำดับความเข้มของการ match — เลือก stock ที่มีของเหลือมากสุดเมื่อ tie
  const candidates = masterItems.filter(m =>
    m.active &&
    m.name === parsed.name &&
    (m.size || '').toLowerCase() === (parsed.size || '').toLowerCase()
  );
  if (candidates.length === 0) return null;
  if (candidates.length === 1) return candidates[0];
  // หลายตัว match → เลือกที่ stock พอ และ stock มากสุด
  // (ไม่ prefer brand ใดเป็นพิเศษ — recruit ควรระบุ brandPreference ถ้ามีหลายแบรนด์)
  const sufficient = candidates.filter(c => Number(c.stockQty) >= Number(parsed.qty));
  const pool = sufficient.length ? sufficient : candidates;
  pool.sort((a, b) => Number(b.stockQty) - Number(a.stockQty));
  return pool[0];
}

// กดทีเดียวสร้าง issue ทุกรายการตามที่ recruit แจ้ง
async function issueAllFromRecruit(requestId) {
  if (!requireHR()) return;
  const req = DB.getUniformRequest(requestId);
  if (!req) return;
  const parsed = parseUniformNoteToItems(req.note);
  const items = DB.getUniformItems({ activeOnly: true });
  const matched = parsed.map(p => ({ parsed: p, item: matchUniformItemFromStock(p, items) })).filter(m => m.item);
  if (matched.length === 0) {
    toast('ไม่พบรายการที่ match กับ stock — เพิ่ม master หรือลงรายการ manual แทน', 'warning');
    return;
  }

  const issuedBy = DB.profile?.name || DB.user?.email || '';
  const issuedDate = document.getElementById('recruitIssueDate')?.value || tz.today();
  let okCount = 0, failCount = 0;
  const failures = [];  // {item, qty, reason}
  for (const m of matched) {
    try {
      await DB.saveUniformIssue({
        requestId,
        itemId: m.item.id,
        itemName: m.item.name,
        size: m.item.size || '',
        qty: m.parsed.qty,
        unitCost: m.item.unitCost,
        issuedDate,
        issuedBy,
        employeeId: req.employeeId || '',
        note: '',
        // [Snapshot] เก็บ brand/color/sku context
        brandSnapshot: m.item.brand || '',
        categorySnapshot: m.item.category || '',
        colorSnapshot: m.item.color || '',
        skuSnapshot: m.item.sku || ''
      });
      okCount++;
    } catch (ex) {
      console.warn('Issue fail:', m.parsed.raw, ex);
      failCount++;
      failures.push({
        item: `${m.item.name} ${m.item.size || ''}`.trim(),
        qty: m.parsed.qty,
        reason: ex.message || String(ex)
      });
    }
  }
  if (failCount === 0) {
    toast(`✓ บันทึก ${okCount} รายการสำเร็จ — stock ถูกตัดอัตโนมัติ`, 'success');
  } else {
    // [Fix] แสดง modal รายงาน fail ละเอียด แทน toast เงียบ
    const failHtml = failures.map(f =>
      `<li><strong>${escapeHtml(f.item)}</strong> × ${f.qty} ชิ้น<br><span class="muted-2" style="font-size:12px;color:var(--danger)">${escapeHtml(f.reason)}</span></li>`
    ).join('');
    modal.open(`⚠️ จัดบางรายการไม่สำเร็จ (${okCount}/${matched.length})`, `
      <div style="background:#fef3c7;padding:10px 14px;border-radius:8px;margin-bottom:14px;font-size:13.5px">
        <strong>${okCount} รายการสำเร็จ</strong> · <strong style="color:var(--danger)">${failCount} รายการล้มเหลว</strong><br>
        <span class="muted-2" style="font-size:12.5px">รายการที่สำเร็จได้บันทึก + ตัด stock แล้ว · ส่วนที่ fail ให้ตรวจดูเหตุผลด้านล่าง</span>
      </div>
      <ul style="margin:0;padding-left:20px;line-height:1.7">${failHtml}</ul>
      <div class="form-actions" style="margin-top:14px">
        <button type="button" class="btn btn-primary" data-close>ปิด</button>
      </div>
    `);
  }
  openIssueItemsForm(requestId); // refresh modal
}

// ─── จัดชุด: เพิ่มรายการ issue ทีละหลายรายการพร้อมกัน ───
function openIssueItemsForm(requestId) {
  if (!requireHR()) return;
  const req = DB.getUniformRequest(requestId);
  if (!req) return;
  // หาเจ้าของคำขอ — รองรับทั้ง employee และ applicant
  let owner = null, ownerLabel = '', refLabel = '';
  if (req.employeeId) {
    const e = DB.getEmployee(req.employeeId);
    if (e) {
      owner = e;
      ownerLabel = `${e.firstName} ${e.lastName || ''} (${req.employeeId})`;
      refLabel = 'พนักงาน';
    }
  }
  if (!owner && req.applicantId) {
    const ap = DB.getApplicant(req.applicantId);
    if (ap) {
      owner = ap;
      ownerLabel = `${ap.firstName} ${ap.lastName || ''} (ผู้สมัคร · ยังไม่ออกรหัสพนักงาน)`;
      refLabel = 'ผู้สมัคร';
    }
  }
  if (!owner) { toast('ไม่พบเจ้าของคำขอ', 'error'); return; }

  // [Feat] กรอง items ตาม brand_preference ของ request (ถ้ามี)
  const allItems = DB.getUniformItems({ activeOnly: true });
  const items = req.brandPreference
    ? allItems.filter(i => i.brand === req.brandPreference)
    : allItems;
  const existing = DB.getUniformIssues({ requestId });
  const issuedBy = DB.profile?.name || DB.user?.email || '';
  const brandObj = req.brandPreference ? DB.getUniformBrand(req.brandPreference) : null;

  const isFromApplicant = refLabel === 'ผู้สมัคร';
  const editLink = isFromApplicant && req.applicantId
    ? `<button type="button" class="btn btn-ghost btn-sm" onclick="modal.close(); openApplicantForm('${escapeHtml(req.applicantId)}')" style="margin-left:8px;font-size:11px">✏️ แก้ไขที่ recruit</button>`
    : (req.employeeId ? `<button type="button" class="btn btn-ghost btn-sm" onclick="modal.close(); openUniformRequestForm('${escapeHtml(req.id)}')" style="margin-left:8px;font-size:11px">✏️ แก้ไขคำขอ</button>` : '');

  modal.open(`บันทึกการจัดชุด — ${escapeHtml(owner.firstName + ' ' + (owner.lastName || ''))}`, `
    ${req.brandPreference ? `
      <div style="background:linear-gradient(90deg, #eff6ff 0%, #dbeafe 100%);padding:10px 14px;border-radius:8px;margin-bottom:14px;border-left:4px solid #1e40af;display:flex;align-items:center;gap:10px;flex-wrap:wrap">
        <strong style="font-size:14px;color:#1e40af">🏷️ แบรนด์ที่ต้องการ:</strong>
        <span class="badge badge-info" style="font-size:12px;background:#1e40af;color:white">${escapeHtml(brandObj?.name || req.brandPreference)}</span>
        <span class="muted-2" style="font-size:12px;flex:1">— dropdown ด้านล่างถูก filter เฉพาะแบรนด์นี้</span>
        <button type="button" class="btn btn-ghost btn-sm" onclick="clearRequestBrandPref('${escapeHtml(req.id)}', '${escapeHtml(requestId)}')" title="ดูสินค้าทุกแบรนด์">เปลี่ยน/ล้าง</button>
      </div>
    ` : ''}
    <div class="form-section">
      <h3>ข้อมูลคำขอ <span class="badge ${isFromApplicant ? 'badge-warning' : 'badge-success'}" style="margin-left:8px;font-size:11px">${refLabel}</span>${editLink}</h3>
      <div class="form-grid">
        <div class="form-group"><label>เจ้าของคำขอ</label><input type="text" readonly value="${escapeHtml(ownerLabel)}"/></div>
        <div class="form-group"><label>ต้องการก่อน</label><input type="text" readonly value="${req.neededBy ? fmt.date(req.neededBy) : '-'}"/></div>
        ${!req.note ? `<div class="form-group span-2">
          <label>รายละเอียดที่ recruit แจ้ง <span class="muted-2" style="font-weight:normal;font-size:11px">(size, ประเภท, จำนวน)</span></label>
          <div style="padding:14px 16px;background:var(--warning-soft);color:var(--warning-text);border-radius:8px;font-size:13px;border:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap">
            <div>⚠️ <strong>ยังไม่ระบุรายละเอียดชุด</strong> — recruit ยังไม่ได้กรอก size/ประเภท/จำนวน${isFromApplicant ? ' ที่ตอนเพิ่มผู้สมัคร' : ''}</div>
            ${isFromApplicant && req.applicantId
              ? `<button type="button" class="btn btn-primary btn-sm" onclick="modal.close(); openApplicantForm('${escapeHtml(req.applicantId)}')">ไปแก้ไขที่ recruit</button>`
              : (req.employeeId ? `<button type="button" class="btn btn-primary btn-sm" onclick="modal.close(); openUniformRequestForm('${escapeHtml(req.id)}')">ไปกรอกรายละเอียด</button>` : '')}
          </div>
        </div>` : ''}
      </div>
    </div>

    ${(() => {
      // panel รายการที่ recruit แจ้ง — ซ่อนถ้าจัดส่งบางส่วนไปแล้ว
      if (existing.length > 0) return '';
      const parsed = parseUniformNoteToItems(req.note);
      if (parsed.length === 0) return '';
      const matched = parsed.map(p => ({ parsed: p, item: matchUniformItemFromStock(p, items) }));
      const matchedCount = matched.filter(m => m.item).length;
      const totalCost = matched.reduce((s, m) => s + (m.item ? m.item.unitCost * m.parsed.qty : 0), 0);
      return `
        <div class="form-section" style="background:var(--surface-2);padding:14px;border-radius:8px;border-left:3px solid var(--primary)">
          <h3 style="margin-top:0">📋 รายการที่ recruit แจ้ง <span class="muted-2" style="font-weight:normal;font-size:12px">(${parsed.length} รายการ · match ${matchedCount}/${parsed.length})</span></h3>
          <div class="table-wrap"><table class="table table-compact" style="font-size:13px;background:var(--surface)">
            <thead><tr><th>รายการ</th><th>size</th><th class="num">qty</th><th>สถานะ match</th><th class="num">ราคา/ชิ้น</th><th class="num">รวม</th></tr></thead>
            <tbody>
              ${matched.map(m => {
                if (!m.parsed.parseable) {
                  return `<tr><td colspan="6" class="muted-2">⚠️ แยกข้อมูลไม่ได้: ${escapeHtml(m.parsed.raw)}</td></tr>`;
                }
                const stockOk = m.item && Number(m.item.stockQty) >= m.parsed.qty;
                return `<tr>
                  <td><strong>${escapeHtml(m.parsed.name)}</strong></td>
                  <td>${escapeHtml(m.parsed.size || '-')}</td>
                  <td class="num">${m.parsed.qty}</td>
                  <td>${m.item
                    ? `<span class="badge ${stockOk ? 'badge-success' : 'badge-warning'}">${stockOk ? '✓ พร้อมส่ง' : `Stock เหลือ ${m.item.stockQty}`}</span>`
                    : '<span class="badge badge-danger">⚠️ ไม่พบใน stock</span>'}</td>
                  <td class="num">${m.item ? fmt.money(m.item.unitCost) : '-'}</td>
                  <td class="num"><strong>${m.item ? fmt.money(m.item.unitCost * m.parsed.qty) : '-'}</strong></td>
                </tr>`;
              }).join('')}
              ${matchedCount > 0 ? `<tr style="background:var(--surface-2);font-weight:600"><td colspan="5" style="text-align:right">รวมที่จะเก็บจากพนักงาน</td><td class="num" style="color:var(--success)">${fmt.money(totalCost)} ฿</td></tr>` : ''}
            </tbody>
          </table></div>
          <div class="form-actions" style="justify-content:flex-end;margin-top:12px;gap:10px;align-items:center;flex-wrap:wrap">
            ${matchedCount > 0
              ? `<label style="font-size:12.5px;color:var(--text-2);display:flex;align-items:center;gap:6px;margin:0">วันที่จัดส่ง:
                  <input type="date" id="recruitIssueDate" value="${tz.today()}" style="padding:6px 10px;font-size:13px;width:auto"/>
                 </label>
                 <button type="button" class="btn btn-primary" onclick="issueAllFromRecruit('${escapeHtml(requestId)}')">🚀 ส่งทั้งหมดตาม recruit (${matchedCount} รายการ)</button>`
              : `<span class="muted-2" style="font-size:12px;color:var(--warning)">⚠️ ไม่มีรายการที่ match กับ stock — เพิ่ม master ก่อน หรือลงรายการ manual ด้านล่าง</span>`}
          </div>
          ${matched.some(m => !m.item) ? `<div class="muted-2" style="font-size:11.5px;color:var(--warning);margin-top:8px;line-height:1.6">💡 รายการที่ match ไม่ได้จะถูกข้าม — ให้ลงรายการเพิ่มแบบ manual ในส่วน "เพิ่มรายการ" ด้านล่าง</div>` : ''}
        </div>
      `;
    })()}

    <div class="form-section">
      <h3>รายการที่จัดให้แล้ว <span class="muted-2" style="font-weight:normal;font-size:12px">(${existing.length} รายการ · รวม ${fmt.money(req.totalCost)} บาท)</span></h3>
      ${existing.length ? `<div class="table-wrap"><table class="table table-compact" style="font-size:13px">
        <thead><tr><th>วันที่</th><th>แบรนด์</th><th>รายการ</th><th>สี</th><th>ขนาด</th><th class="num">จำนวน</th><th class="num">ราคา</th><th class="num">รวม</th><th></th></tr></thead>
        <tbody>
          ${existing.map(i => {
            const item = DB.getUniformItem(i.itemId);
            const brand = i.brandSnapshot || item?.brand || '-';
            const color = i.colorSnapshot || item?.color || '';
            return `<tr>
              <td>${fmt.date(i.issuedDate)}</td>
              <td><span class="badge badge-info" style="font-size:11px">${escapeHtml(brand)}</span></td>
              <td>${escapeHtml(i.itemName)}${i.skuSnapshot ? `<br><span class="muted-2" style="font-family:monospace;font-size:10.5px">${escapeHtml(i.skuSnapshot)}</span>` : ''}</td>
              <td>${color ? `<span style="display:inline-block;width:10px;height:10px;border-radius:99px;background:${getColorHex(color)};margin-right:4px;border:1px solid #ccc;vertical-align:middle"></span>${escapeHtml(color)}` : '-'}</td>
              <td>${escapeHtml(i.size || '-')}</td>
              <td class="num">${i.qty}</td>
              <td class="num">${fmt.money(i.unitCost)}</td>
              <td class="num">${fmt.money(i.totalCost)}</td>
              <td><button class="btn btn-ghost btn-sm" onclick="(async () => { if (await modal.confirm('ลบรายการ','คืน stock + ลบรายการ?')) { await DB.deleteUniformIssue('${escapeHtml(i.id)}'); toast('ลบแล้ว','success'); openIssueItemsForm('${escapeHtml(requestId)}'); } })()">ลบ</button></td>
            </tr>`;
          }).join('')}
        </tbody>
      </table></div>` : '<div class="muted-2" style="padding:12px 0">— ยังไม่มี —</div>'}
    </div>

    <div class="form-section">
      <h3>เพิ่มรายการ</h3>
      <form id="issueForm">
        <div class="form-grid">
          <div class="form-group span-2"><label>เลือกชุด * <span class="muted-2" style="font-weight:normal;font-size:11px">(แสดงเฉพาะ stock > 0 และ active)</span></label>
            <select name="itemId" id="issueItem" required>
              <option value="">— เลือกรายการ —</option>
              ${(() => {
                // group by brand → optgroup
                const byBrand = new Map();
                for (const i of items) {
                  if (Number(i.stockQty) <= 0) continue;  // ซ่อน stock หมด
                  const key = i.brand || '(ไม่ระบุ)';
                  if (!byBrand.has(key)) byBrand.set(key, []);
                  byBrand.get(key).push(i);
                }
                const brandNames = new Map(DB.getUniformBrands().map(b => [b.code, b.name]));
                return [...byBrand.keys()].sort().map(brandKey => {
                  const brandLabel = brandNames.get(brandKey) || brandKey;
                  const itemsInBrand = byBrand.get(brandKey);
                  return `<optgroup label="🏷️ ${escapeHtml(brandLabel)}">${
                    itemsInBrand.map(i => {
                      const desc = [
                        i.name,
                        i.color ? `(${i.color})` : '',
                        i.size ? `· ${i.size}` : '',
                        `· เหลือ ${i.stockQty} ชิ้น`,
                        `· ${fmt.money(i.unitCost)} ฿`
                      ].filter(Boolean).join(' ');
                      return `<option value="${i.id}"
                        data-name="${escapeHtml(i.name)}"
                        data-size="${escapeHtml(i.size || '')}"
                        data-cost="${i.unitCost}"
                        data-stock="${i.stockQty}"
                        data-brand="${escapeHtml(i.brand || '')}"
                        data-category="${escapeHtml(i.category || '')}"
                        data-color="${escapeHtml(i.color || '')}"
                        data-sku="${escapeHtml(i.sku || '')}"
                      >${escapeHtml(desc)}</option>`;
                    }).join('')
                  }</optgroup>`;
                }).join('');
              })()}
            </select>
          </div>
          <div class="form-group"><label>จำนวน *</label><input name="qty" id="issueQty" type="number" min="1" value="1" required/></div>
          <div class="form-group"><label>ราคา/ชิ้น</label><input name="unitCost" id="issueCost" type="number" min="0" step="0.01" readonly/></div>
          <div class="form-group"><label>วันที่จัดส่ง *</label><input name="issuedDate" type="date" value="${tz.today()}" required/></div>
          <div class="form-group"><label>HR ผู้จัด</label><input name="issuedBy" value="${escapeHtml(issuedBy)}"/></div>
          <div class="form-group"><label>รวม</label><input id="issueTotal" type="text" readonly style="font-weight:600;color:var(--success)"/></div>
          <div class="form-group span-2"><label>หมายเหตุ</label><input name="note" placeholder="เช่น ส่งให้พนักงานเรียบร้อย"/></div>
        </div>
        <div class="form-actions" style="justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap">
          <div style="display:flex;gap:8px;flex-wrap:wrap">
            <button type="button" class="btn btn-secondary" data-close>ปิด</button>
            ${req.status !== 'issued' && req.status !== 'cancelled' ? `
              <button type="button" class="btn btn-success" onclick="markUniformRequestIssued('${escapeHtml(requestId)}')" title="ทำเครื่องหมายว่าจัดส่งครบแล้ว (เปลี่ยนสถานะเป็น 'จัดส่งแล้ว')">
                ✓ จัดส่งครบแล้ว
              </button>
            ` : `<button type="button" class="btn btn-success" onclick="confirmIssueAndClose('${escapeHtml(requestId)}')" title="ยืนยันการจัดส่งเรียบร้อย + ปิดหน้านี้">
                ✓ ยืนยันการจัดส่ง · ปิด
              </button>`}
          </div>
          <button type="submit" class="btn btn-primary">+ เพิ่มรายการ${existing.length === 0 ? ' (พร้อมตัด stock)' : ''}</button>
        </div>
      </form>
    </div>
    <div class="muted-2" style="font-size:12px;padding:12px 14px;background:var(--surface-2);border-radius:8px;margin-top:14px;line-height:1.7">
      <strong style="color:var(--text)">📌 คำแนะนำ:</strong><br>
      • <strong>"+ เพิ่มรายการ"</strong> — บันทึกแต่ละชิ้นที่จัดให้ พร้อมตัด stock + คิดค่าชุดอัตโนมัติ<br>
      • <strong>"✓ จัดส่งครบแล้ว"</strong> — ทำเครื่องหมายว่าจบ (เปลี่ยนสถานะเป็น "จัดส่งแล้ว") เมื่อไม่ต้องการลงรายการรายชิ้น<br>
      • <strong>"ปิด"</strong> — ออกจากหน้านี้โดยไม่เปลี่ยนสถานะ
    </div>
  `, { size: 'lg' });

  const updateCost = () => {
    const sel = $('#issueItem');
    const opt = sel.options[sel.selectedIndex];
    const cost = opt ? Number(opt.dataset.cost || 0) : 0;
    const qty = Number($('#issueQty').value || 0);
    $('#issueCost').value = cost;
    $('#issueTotal').value = fmt.money(cost * qty);
  };
  $('#issueItem')?.addEventListener('change', updateCost);
  $('#issueQty')?.addEventListener('input', updateCost);

  $('#issueForm').addEventListener('submit', async (e) => {
    e.preventDefault();
    try {
      const data = Object.fromEntries(new FormData(e.target).entries());
      const sel = $('#issueItem');
      const opt = sel.options[sel.selectedIndex];
      data.itemName = opt?.dataset.name || '';
      data.size = opt?.dataset.size || '';
      // [Snapshot] เก็บ brand/color/sku context ลง row นี้ — กันข้อมูลหายตอน item ถูกแก้/ลบ
      data.brandSnapshot    = opt?.dataset.brand || '';
      data.categorySnapshot = opt?.dataset.category || '';
      data.colorSnapshot    = opt?.dataset.color || '';
      data.skuSnapshot      = opt?.dataset.sku || '';
      data.requestId = requestId;
      // employee_id อาจยังว่าง ถ้า applicant ยังไม่รับเข้า — issue จะ link ผ่าน request_id ก่อน
      data.employeeId = req.employeeId || '';
      data.qty = Number(data.qty);
      data.unitCost = Number(data.unitCost);
      const stock = Number(opt?.dataset.stock || 0);
      // [Stock] DB trigger จะ reject ถ้า qty > stock — block ที่ UI ก่อนเพื่อ UX
      if (data.qty > stock) {
        if (stock === 0) {
          toast(`Stock หมด — กรุณาเพิ่ม Stock ก่อนจัด หรือเลือกขนาดอื่น`, 'error');
        } else {
          toast(`Stock ไม่พอ — เหลือ ${stock} ชิ้น แต่ต้องการ ${data.qty} ชิ้น`, 'error');
        }
        return;
      }
      await DB.saveUniformIssue(data);
      toast('เพิ่มรายการแล้ว · stock ถูกตัดอัตโนมัติ', 'success');
      openIssueItemsForm(requestId); // refresh modal
    } catch (ex) { toast('บันทึกไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
  });
}

// ─── รายการชุด (master) ───
function openUniformItemForm(id = null) {
  if (!requireHR()) return;
  // [Brand] Default ใช้ brand แรกใน list (ไม่ใช่ KB) — ลบ KB ที่เป็นชื่อบริษัทแล้ว
  const _defaultBrandCode = (DB.getUniformBrands({ activeOnly: true })[0]?.code) || '';
  const i = id ? DB.getUniformItem(id) : {
    id: '', name: '', size: '', stockQty: 0, unitCost: 0, active: true, note: '',
    brand: _defaultBrandCode, category: '', color: '', sku: '', reorderPoint: 5,
    supplier: '', gender: 'unisex', material: '', imageUrl: ''
  };
  const brands = DB.getUniformBrands({ activeOnly: true });
  const categories = DB.getUniformDistinctCategories();
  const colors = DB.getUniformDistinctColors();
  const sizes = DB.getUniformDistinctSizes();

  modal.open(id ? '✎ แก้ไขรายการชุด' : '+ เพิ่มรายการชุด', `
    <form id="uniItemForm">
      <div style="background:#eff6ff;padding:8px 12px;border-radius:6px;margin-bottom:14px;font-size:13px;color:#1e40af">
        💡 <strong>เคล็ดลับ:</strong> ตั้งค่าให้ครบ (แบรนด์, หมวด, สี, SKU) จะช่วยให้ค้นหา/กรอง stock ได้ง่าย รองรับการขยายแบรนด์ใหม่ในอนาคต
      </div>

      <h4 style="margin:0 0 10px 0;color:var(--text);font-size:14px">📦 ข้อมูลหลัก</h4>
      <div class="form-grid">
        <div class="form-group">
          <label>แบรนด์ ${brands.length ? '*' : ''}</label>
          ${brands.length ? `
            <select name="brand" ${brands.length === 1 ? '' : 'required'}>
              ${brands.length > 1 ? '<option value="">— ไม่ระบุแบรนด์ —</option>' : ''}
              ${brands.map(b => `<option value="${escapeHtml(b.code)}" ${b.code === i.brand ? 'selected' : ''}>${escapeHtml(b.name)}</option>`).join('')}
            </select>
          ` : `
            <input name="brand" value="" readonly placeholder="ยังไม่มีแบรนด์ในระบบ"/>
            <small class="muted-2" style="font-size:11px;color:var(--warning)">⚠ กรุณาเพิ่มแบรนด์ที่ "🏷️ แบรนด์" ก่อน — กดบันทึกได้ แต่ item จะไม่มีแบรนด์</small>
          `}
        </div>
        <div class="form-group">
          <label>หมวด *</label>
          <input name="category" list="dl-uni-cats" value="${escapeHtml(i.category)}" required placeholder="เช่น เสื้อ, กางเกง"/>
          <datalist id="dl-uni-cats">${['เสื้อ','กางเกง','กระโปรง','หมวก','รองเท้า','ถุงเท้า','อุปกรณ์',...categories].filter((v,j,a)=>a.indexOf(v)===j).map(v => `<option value="${escapeHtml(v)}">`).join('')}</datalist>
        </div>
        <div class="form-group span-2">
          <label>ชื่อชุด *</label>
          <input name="name" list="dl-uni-names" value="${escapeHtml(i.name)}" required placeholder="เช่น เสื้อยูนิฟอร์มแขนสั้น"/>
          <datalist id="dl-uni-names">${['เสื้อยูนิฟอร์ม','เสื้อแขนสั้น','เสื้อแขนยาว','เสื้อโปโล','กางเกงขายาว','กางเกงขาสั้น','กระโปรง','หมวก','รองเท้า','ผ้ากันเปื้อน','เนคไท','เข็มขัด'].map(v => `<option value="${v}">`).join('')}</datalist>
        </div>

        <div class="form-group">
          <label>ขนาด</label>
          <input name="size" list="dl-uni-sizes" value="${escapeHtml(i.size)}" placeholder="S, M, L, XL, 36"/>
          <datalist id="dl-uni-sizes">${['S','M','L','XL','XXL','XXXL','ฟรีไซส์','36','38','40','42','44',...sizes].filter((v,j,a)=>a.indexOf(v)===j).map(v => `<option value="${escapeHtml(v)}">`).join('')}</datalist>
        </div>
        <div class="form-group">
          <label>สี</label>
          <input name="color" list="dl-uni-colors" value="${escapeHtml(i.color)}" placeholder="เช่น ขาว, น้ำเงิน"/>
          <datalist id="dl-uni-colors">${['ขาว','ดำ','น้ำเงิน','กรมท่า','แดง','เขียว','เหลือง','ส้ม','ม่วง','ชมพู','น้ำตาล','เทา','ครีม','ฟ้า',...colors].filter((v,j,a)=>a.indexOf(v)===j).map(v => `<option value="${escapeHtml(v)}">`).join('')}</datalist>
        </div>
        <div class="form-group">
          <label>เพศ</label>
          <select name="gender">
            <option value="unisex" ${i.gender === 'unisex' ? 'selected' : ''}>⚧ Unisex (ทุกเพศ)</option>
            <option value="male" ${i.gender === 'male' ? 'selected' : ''}>♂ ชาย</option>
            <option value="female" ${i.gender === 'female' ? 'selected' : ''}>♀ หญิง</option>
          </select>
        </div>
        <div class="form-group">
          <label>เนื้อผ้า/วัสดุ</label>
          <input name="material" value="${escapeHtml(i.material)}" placeholder="เช่น Cotton 100%, Poly-Cotton 65/35"/>
        </div>

        <div class="form-group span-2">
          <label>SKU (รหัสสากล) <span class="muted-2" style="font-weight:normal;font-size:11px">— สร้างอัตโนมัติได้ ⤵</span></label>
          <div style="display:flex;gap:6px">
            <input name="sku" id="itemSkuInput" value="${escapeHtml(i.sku)}" placeholder="เช่น KB-SHRT-M-WH" style="flex:1;font-family:monospace"/>
            <button type="button" class="btn btn-secondary btn-sm" onclick="autoGenerateSKU()" title="สร้าง SKU จาก brand+หมวด+ขนาด+สี">↻ สร้างอัตโนมัติ</button>
          </div>
          <small class="muted-2" style="font-size:11px">Format: BRAND-CATEGORY-SIZE-COLOR (เช่น KB-SHRT-M-WHITE)</small>
        </div>
      </div>

      <h4 style="margin:18px 0 10px 0;color:var(--text);font-size:14px">📊 Stock & ราคา</h4>
      <div class="form-grid">
        <div class="form-group">
          <label>จำนวนใน Stock</label>
          <input name="stockQty" type="number" min="0" value="${i.stockQty}" ${id ? 'readonly title="แก้ไขผ่านปุ่ม รับเข้า/ปรับ เพื่อบันทึก ledger"' : ''}/>
          ${id ? '<small class="muted-2" style="font-size:11px">⚠ แก้ stock direct จะไม่ลง ledger — ใช้ปุ่ม "+ รับเข้า" หรือ "ปรับ" แทน</small>' : ''}
        </div>
        <div class="form-group">
          <label>จุดสั่งซื้อ (Reorder Point)</label>
          <input name="reorderPoint" type="number" min="0" value="${i.reorderPoint}" placeholder="5"/>
          <small class="muted-2" style="font-size:11px">เตือนเมื่อ stock ต่ำกว่าค่านี้</small>
        </div>
        <div class="form-group">
          <label>ราคา/ชิ้น (บาท)</label>
          <input name="unitCost" type="number" min="0" step="0.01" value="${i.unitCost}"/>
        </div>
        <div class="form-group">
          <label>สถานะ</label>
          <select name="active">
            <option value="true" ${i.active ? 'selected' : ''}>✓ ใช้งาน</option>
            <option value="false" ${!i.active ? 'selected' : ''}>⊘ ปิดใช้งาน</option>
          </select>
        </div>
      </div>

      <h4 style="margin:18px 0 10px 0;color:var(--text);font-size:14px">🏭 Supplier & รูป</h4>
      <div class="form-grid">
        <div class="form-group span-2">
          <label>ผู้ผลิต/Supplier</label>
          <input name="supplier" value="${escapeHtml(i.supplier)}" placeholder="ชื่อโรงงาน/บริษัทผู้ผลิต"/>
        </div>
        <div class="form-group span-2">
          <label>URL รูปภาพ <span class="muted-2" style="font-weight:normal;font-size:11px">(optional)</span></label>
          <input name="imageUrl" type="url" value="${escapeHtml(i.imageUrl)}" placeholder="https://..."/>
        </div>
        <div class="form-group span-2">
          <label>หมายเหตุ</label>
          <textarea name="note" rows="2" placeholder="ข้อมูลเพิ่มเติม">${escapeHtml(i.note)}</textarea>
        </div>
      </div>

      <div class="form-actions">
        <button type="button" class="btn btn-secondary" data-close>ยกเลิก</button>
        <button type="submit" class="btn btn-primary">บันทึก</button>
      </div>
    </form>
  `);
  $('#uniItemForm').addEventListener('submit', async (e) => {
    e.preventDefault();
    try {
      const data = Object.fromEntries(new FormData(e.target).entries());
      data.stockQty = Number(data.stockQty || 0);
      data.unitCost = Number(data.unitCost || 0);
      data.reorderPoint = Number(data.reorderPoint || 5);
      data.active = data.active === 'true';
      if (id) {
        data.id = id;
        // ป้องกัน stockQty override (readonly) — เก็บค่าเดิมจาก DB
        const orig = DB.getUniformItem(id);
        if (orig) data.stockQty = orig.stockQty;
      }
      await DB.saveUniformItem(data);
      modal.close();
      toast(id ? 'บันทึกแล้ว' : 'เพิ่มรายการชุดแล้ว', 'success');
      _uniformState.tab = 'items';
      router.go('uniform');
    } catch (ex) { toast('บันทึกไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
  });
}

// ── Helper: Auto-generate SKU ──
function autoGenerateSKU() {
  const form = document.getElementById('uniItemForm');
  if (!form) return;
  const brand = (form.brand?.value || '').toUpperCase();
  if (!brand) {
    toast('กรุณาเลือกแบรนด์ก่อน — SKU ต้องมีแบรนด์', 'warning');
    return;
  }
  const cat = form.category?.value || '';
  const catCode = ({
    'เสื้อ': 'SHRT', 'กางเกง': 'PANT', 'กระโปรง': 'SKRT',
    'หมวก': 'CAP', 'รองเท้า': 'SHOE', 'ถุงเท้า': 'SOCK',
    'อุปกรณ์': 'ACC'
  })[cat] || (cat.slice(0, 4).toUpperCase() || 'ITEM');
  const size = (form.size?.value || 'FREE').toUpperCase().replace(/\s+/g, '');
  const color = (form.color?.value || '').toUpperCase().replace(/\s+/g, '').slice(0, 5);
  const sku = [brand, catCode, size, color].filter(Boolean).join('-');
  const skuInput = document.getElementById('itemSkuInput');
  if (skuInput) skuInput.value = sku;
}

// ─── Modal: จัดการ Brands ───
