      'ค่าตำแหน่งใหม่': 2000, 'ค่าเดินทางใหม่': '', 'ค่าอาหารใหม่': '',
      'ค่าเบี้ยเลี้ยงใหม่': '', 'ค่าภาษาใหม่': '', 'ค่าโทรศัพท์ใหม่': '', 'ค่าอื่นๆใหม่': '',
