// ═══════════════════════════════════════════════════════════
// Phase 4 — LIVE Permission Matrix editor
// admin tick เปิด/ปิดสิทธิ์ของแต่ละ role → save ผ่าน RPC set_role_permissions
// ═══════════════════════════════════════════════════════════
const SCOPE_META = {
  employee: { icon: '👥', label: 'พนักงาน',         color: 'var(--info-text)' },
  payroll:  { icon: '💰', label: 'เงินเดือน',        color: 'var(--warning-text)' },
  leave:    { icon: '📅', label: 'ลา / กะ / ปฏิทิน', color: 'var(--success-text)' },
  system:   { icon: '⚙️', label: 'ตั้งค่าระบบ',     color: 'var(--gold-text)' }
};
const _permMatrixState = {
  roles: null, perms: null, current: null, draft: null,
  collapsed: new Set(),  // scope keys ที่ user ย่อไว้
  loading: false, error: null
};

// ─── Auto-detect permission keys ที่ใช้ใน code แต่ไม่อยู่ใน DB matrix ───
// สแกน script (inline + external same-origin) หา hasPermission/requirePermission/user_has_permission
// cache ผลไว้ใน module level — รัน fetch แค่ครั้งแรก (text ของ script ไม่เปลี่ยน)
let _cachedUsedPerms = null;
async function _scanScriptsForPerms() {
  if (_cachedUsedPerms) return _cachedUsedPerms;
  const usedKeys = new Set();
  const patterns = [
    /\bhasPermission\(\s*['"`]([a-z_]+\.[a-z_]+)['"`]\s*\)/g,
    /\brequirePermission\(\s*['"`]([a-z_]+\.[a-z_]+)['"`]/g,
    /\buser_has_permission\(\s*['"`]([a-z_]+\.[a-z_]+)['"`]\s*\)/g
  ];
  const scriptPromises = [];
  for (const script of document.scripts) {
    let inlineText = script.textContent || '';
    if (inlineText) {
      scriptPromises.push(Promise.resolve(inlineText));
    } else if (script.src) {
      // fetch external scripts ที่เป็น same-origin (กัน CORS ของ CDN)
      try {
        const url = new URL(script.src, window.location.href);
        if (url.origin === window.location.origin) {
          scriptPromises.push(
            fetch(url.toString())
              .then(r => r.ok ? r.text() : '')
              .catch(() => '')
          );
        }
      } catch (e) { /* invalid URL — skip */ }
    }
  }
  const texts = await Promise.all(scriptPromises);
  for (const text of texts) {
    if (!text) continue;
    for (const re of patterns) {
      re.lastIndex = 0;
      let m;
      while ((m = re.exec(text)) !== null) {
        if (m[1]) usedKeys.add(m[1]);
      }
    }
  }
  _cachedUsedPerms = usedKeys;
  return usedKeys;
}

async function diagnosePermissions(dbKeys) {
  const dbSet = new Set(dbKeys || []);
  const usedKeys = await _scanScriptsForPerms();
  const missing = [...usedKeys].filter(k => !dbSet.has(k)).sort();
  return { missing, usedKeys: [...usedKeys].sort(), dbKeys: [...dbSet] };
}

// แสดง modal ลงทะเบียน permission ที่ขาด — เรียก RPC register_permission
async function openRegisterPermissionModal(key) {
  // เดา scope จาก prefix
  const prefix = key.split('.')[0];
  const guessScope =
    ['employee', 'applicant', 'blacklist', 'uniform', 'sso'].includes(prefix) ? 'employee'
    : ['payroll', 'salary', 'loan', 'advance', 'allowance', 'evaluation', 'report'].includes(prefix) ? 'payroll'
    : ['leave', 'holiday', 'holiday_swap', 'schedule', 'leave_calendar'].includes(prefix) ? 'leave'
    : 'system';
  return new Promise((resolve) => {
    modal.open(`ลงทะเบียน permission ใหม่`, `
      <div class="form-grid">
        <div class="form-group span-2">
          <label>Permission key</label>
          <input value="${escapeHtml(key)}" readonly style="font-family:monospace;background:var(--surface-2)"/>
        </div>
        <div class="form-group span-2">
          <label>ชื่อแสดงผล (ภาษาไทย)</label>
          <input id="regPermLabel" required placeholder="เช่น เห็นเมนูตารางงาน" />
        </div>
        <div class="form-group">
          <label>กลุ่ม</label>
          <select id="regPermScope">
            <option value="employee" ${guessScope === 'employee' ? 'selected' : ''}>employee</option>
            <option value="payroll" ${guessScope === 'payroll' ? 'selected' : ''}>payroll</option>
            <option value="leave" ${guessScope === 'leave' ? 'selected' : ''}>leave</option>
            <option value="system" ${guessScope === 'system' ? 'selected' : ''}>system</option>
          </select>
        </div>
        <div class="form-group">
          <label>ความอันตราย</label>
          <select id="regPermDanger">
            <option value="false">ปกติ</option>
            <option value="true">DANGER (สิทธิ์เสี่ยง)</option>
          </select>
        </div>
        <div class="form-group span-2">
          <label>คำอธิบาย (ทางเลือก)</label>
          <textarea id="regPermDesc" rows="2" placeholder="อธิบายว่า permission นี้ใช้ทำอะไร"></textarea>
        </div>
      </div>
      <div style="font-size:12.5px;color:var(--text-2);padding:10px;background:var(--surface-2);border-radius:8px;margin-top:8px">
        💡 หลังลงทะเบียน — admin จะถูกตั้งเป็น "เปิด" โดย default (ปลอดภัย) — เปิดให้ role อื่นใน matrix
      </div>
    `, {
      size: 'sm',
      footer: '<button class="btn btn-secondary" data-cancel>ยกเลิก</button><button class="btn btn-primary" data-ok>ลงทะเบียน</button>'
    });
    const root = document.getElementById('modalRoot');
    root.querySelector('[data-ok]').addEventListener('click', async () => {
      const label = document.getElementById('regPermLabel').value.trim();
      const scope = document.getElementById('regPermScope').value;
      const danger = document.getElementById('regPermDanger').value === 'true';
      const desc = document.getElementById('regPermDesc').value.trim();
      if (!label) { toast('กรอกชื่อก่อน', 'error'); return; }
      try {
        const { error } = await DB.client.rpc('register_permission', {
          p_key: key,
          p_scope: scope,
          p_label_th: label,
          p_description: desc,
          p_is_dangerous: danger,
          p_sort_order: 9000
        });
        if (error) throw error;
        modal.close();
        toast(`✓ ลงทะเบียน ${key} แล้ว — รีโหลดตารางสิทธิ์`, 'success');
        renderPermMatrix();
        resolve(true);
      } catch (ex) {
        toast('ลงทะเบียนไม่สำเร็จ: ' + (ex.message || ex), 'error');
      }
    });
    root.querySelector('[data-cancel]').addEventListener('click', () => { modal.close(); resolve(false); });
  });
}

async function renderPermMatrix() {
  if (!DB.isAdmin) return;
  const box = document.getElementById('permMatrixBox');
  if (!box) return;
  _permMatrixState.loading = true;
  box.innerHTML = `<div class="muted-2" style="padding:24px;text-align:center">กำลังโหลดตารางสิทธิ์...</div>`;
  try {
    const [roles, perms, current] = await Promise.all([
      DB.getPermRoles(),
      DB.getPermCatalog(),
      DB.getRolePermissions()
    ]);
    _permMatrixState.roles = roles;
    _permMatrixState.perms = perms;
    _permMatrixState.current = current;
    // ถ้า migration ยังไม่รัน → ทั้งหมดเป็น null
    if (!roles || !perms || !current) {
      _permMatrixState.error = 'migration_not_run';
      box.innerHTML = _renderMatrixEmptyState();
      return;
    }
    // initial draft = current state (clone)
    _permMatrixState.draft = new Map();
    for (const r of roles) {
      _permMatrixState.draft.set(r.id, new Set(current.get(r.id) || []));
    }
    _permMatrixState.loading = false;
    _permMatrixState.error = null;
    // [PERF] render matrix ทันทีหลังได้ data (3 query เร็ว) — ไม่รอ diagnosis
    //   เดิม: await diagnosePermissions() block ที่นี่ → ต้อง fetch app.js+data.js (ไฟล์ใหญ่)
    //         + regex สแกน ก่อน render → หน่วงหลายวินาทีตอนเข้าหน้าครั้งแรก
    //   ใหม่: render เลย + รัน diagnosis เป็น background → inject banner ทีหลัง (progressive)
    box.innerHTML = `<div id="permDiagBanner"></div>` + _renderMatrixHtml();
    _wireMatrixEvents();

    // ─── [Auto-detect] background scan — รันตอน browser ว่าง (idle) เท่านั้น ───
    //   [PERF] เดิมรันทันทีหลัง render → regex สแกน app.js (~1.1MB) บน main thread → หน่วงตาราง
    //   ใหม่: เลื่อนไป requestIdleCallback → ไม่แย่งเวลา paint/scroll/click ของ matrix
    const dbKeys = perms.map(p => p.key);
    const _runPermDiag = () => diagnosePermissions(dbKeys).then(diagnosis => {
      if (!diagnosis || !diagnosis.missing.length) return;
      const bannerBox = document.getElementById('permDiagBanner');
      if (!bannerBox) return;  // user เปลี่ยนหน้าไปแล้ว
      bannerBox.innerHTML = `
        <div class="card" style="border:2px solid var(--warning);background:rgba(217,119,6,0.04);margin-bottom:14px;padding:14px">
          <div style="display:flex;gap:10px;align-items:flex-start">
            <div style="font-size:24px;line-height:1">🔔</div>
            <div style="flex:1">
              <div style="font-weight:700;color:var(--warning);font-size:14px;margin-bottom:4px">
                พบ permission key ใน code ที่ยังไม่อยู่ใน matrix (${diagnosis.missing.length} ตัว)
              </div>
              <div class="muted-2" style="font-size:12.5px;margin-bottom:10px">
                Auto-detect สแกน <code>hasPermission()</code> / <code>requirePermission()</code> ใน script
                แล้วเทียบกับฐานข้อมูล — ฟีเจอร์ใหม่ที่เพิ่ม code แต่ลืม seed จะขึ้นที่นี่
              </div>
              <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px">
                ${diagnosis.missing.map(k => `
                  <button type="button" class="btn btn-warning btn-sm" data-register-perm="${escapeHtml(k)}" style="font-family:monospace;font-size:12px;padding:4px 10px">
                    + ${escapeHtml(k)}
                  </button>
                `).join('')}
              </div>
              <div class="muted-2" style="font-size:11.5px">
                💡 คลิก permission แต่ละตัวเพื่อ "ลงทะเบียน" เข้าระบบ — แล้วจะเปิด/ปิดสิทธิ์ใน matrix ด้านล่างได้
              </div>
            </div>
          </div>
        </div>
      `;
      bannerBox.querySelectorAll('[data-register-perm]').forEach(btn => {
        btn.addEventListener('click', () => {
          openRegisterPermissionModal(btn.dataset.registerPerm);
        });
      });
    }).catch(() => { /* diagnosis ล้มเหลว → เงียบ ไม่กระทบ matrix */ });
    (window.requestIdleCallback || ((cb) => setTimeout(cb, 400)))(_runPermDiag);
  } catch (ex) {
    _permMatrixState.error = ex?.message || String(ex);
    box.innerHTML = `<div class="empty-state" style="padding:24px">
      <div style="color:var(--danger);font-weight:600">โหลดไม่สำเร็จ</div>
      <div class="muted-2" style="margin-top:6px;font-size:12.5px">${escapeHtml(_permMatrixState.error)}</div>
    </div>`;
  }
}

function _renderMatrixEmptyState() {
  return `
    <div class="pm-empty">
      <div class="pm-empty-icon">📋</div>
      <div class="pm-empty-title">ยังไม่ได้รัน Migration</div>
      <div class="pm-empty-body">
        ตารางสิทธิ์ใช้งานจริงต้องการ migration <code>supabase-migration-permissions-v1.sql</code><br>
        ไปที่ Supabase SQL Editor → paste ไฟล์ → Run → กด F5 ที่หน้านี้
      </div>
      <div class="pm-empty-hint">
        ระหว่างนี้ระบบใช้ <strong>กฎเดิม</strong> (isHR / isAdmin) — การใช้งานปกติ ไม่กระทบ
      </div>
    </div>`;
}

function _changedCount() {
  const d = _permMatrixState.draft, c = _permMatrixState.current;
  if (!d || !c) return 0;
  let n = 0;
  for (const [roleId, set] of d) {
    const orig = c.get(roleId) || new Set();
    if (set.size !== orig.size) { n += Math.abs(set.size - orig.size); continue; }
    for (const k of set) if (!orig.has(k)) n++;
  }
  return n;
}

function _renderMatrixHtml() {
  const { roles, perms, draft, current, collapsed } = _permMatrixState;
  // group perms by scope (รักษา sort_order)
  const byScope = new Map();
  for (const p of perms) {
    if (!byScope.has(p.scope)) byScope.set(p.scope, []);
    byScope.get(p.scope).push(p);
  }
  const changed = _changedCount();

  return `
    <div class="pm-toolbar">
      <div class="pm-search">
        <input type="search" id="pmSearchInput" placeholder="ค้นหาสิทธิ์..." aria-label="ค้นหา"/>
      </div>
      <div class="pm-toolbar-stats">
        <span class="pm-stat"><strong>${roles.length}</strong> roles</span>
        <span class="pm-stat"><strong>${perms.length}</strong> permissions</span>
        <span class="pm-stat pm-stat-changed" data-pm-changed style="${changed ? '' : 'display:none'}">
          <strong id="pmChangedNum">${changed}</strong> การเปลี่ยนแปลง
        </span>
      </div>
      <div class="pm-actions">
        <button type="button" class="btn btn-ghost btn-sm" id="pmAddRoleBtn" title="สร้าง role ใหม่">+ Role</button>
        <button type="button" class="btn btn-secondary btn-sm" id="pmResetBtn" ${changed ? '' : 'disabled'}>คืนค่า</button>
        <button type="button" class="btn btn-primary btn-sm" id="pmSaveBtn" ${changed ? '' : 'disabled'}>บันทึก</button>
      </div>
    </div>

    <div class="pm-matrix-wrap">
      <table class="pm-matrix">
        <thead>
          <tr>
            <th class="pm-th-perm">Permission</th>
            ${roles.map(r => `
              <th class="pm-th-role" data-role="${escapeHtml(r.id)}">
                <div class="pm-role-label">
                  ${escapeHtml(r.label_th)}
                  ${!r.is_system ? `
                    <span class="pm-role-actions">
                      <button type="button" class="pm-role-edit" data-pm-edit-role="${escapeHtml(r.id)}" title="แก้ไข">✎</button>
                      <button type="button" class="pm-role-del"  data-pm-del-role="${escapeHtml(r.id)}"  title="ลบ">🗑</button>
                    </span>` : ''}
                </div>
                <div class="pm-role-sub">${escapeHtml(r.id)}${r.is_protected ? ' 🔒' : ''}${r.is_system ? ' · system' : ''}</div>
              </th>
            `).join('')}
          </tr>
        </thead>
        <tbody>
          ${Array.from(byScope.entries()).map(([scope, items]) => {
            const meta = SCOPE_META[scope] || { icon: '•', label: scope };
            const isCollapsed = collapsed.has(scope);
            return `
              <tr class="pm-scope-row" data-scope="${escapeHtml(scope)}">
                <td colspan="${roles.length + 1}" class="pm-scope-header">
                  <button type="button" class="pm-scope-toggle" data-scope-toggle="${escapeHtml(scope)}" aria-expanded="${!isCollapsed}">
                    <span class="pm-scope-chevron">${isCollapsed ? '▸' : '▾'}</span>
                    <span class="pm-scope-icon">${meta.icon}</span>
                    <span class="pm-scope-label">${escapeHtml(meta.label)}</span>
                    <span class="pm-scope-count">${items.length}</span>
                  </button>
                </td>
              </tr>
              ${isCollapsed ? '' : items.map(p => {
                const isCritical = p.is_critical;
                const isDangerous = p.is_dangerous;
                return `
                  <tr class="pm-perm-row" data-scope-rows="${escapeHtml(scope)}" data-search="${escapeHtml((p.key + ' ' + p.label_th).toLowerCase())}">
                    <td class="pm-perm-cell">
                      <div class="pm-perm-label">
                        ${escapeHtml(p.label_th)}
                        ${isCritical ? '<span class="pm-tag pm-tag-critical" title="safety lock — ทุก role ต้องเปิด">CRITICAL</span>' : ''}
                        ${isDangerous ? '<span class="pm-tag pm-tag-dangerous" title="sensitive permission">DANGER</span>' : ''}
                      </div>
                      <div class="pm-perm-key">${escapeHtml(p.key)}</div>
                      ${p.description ? `<div class="pm-perm-desc">${escapeHtml(p.description)}</div>` : ''}
                    </td>
                    ${roles.map(r => {
                      const curr = (current.get(r.id) || new Set()).has(p.key);
                      const next = (draft.get(r.id)  || new Set()).has(p.key);
                      const dirty = curr !== next;
                      const locked = isCritical || (r.is_protected && isDangerous);
                      return `
                        <td class="pm-cell ${dirty ? 'is-dirty' : ''} ${locked ? 'is-locked' : ''}"
                            data-role="${escapeHtml(r.id)}" data-perm="${escapeHtml(p.key)}">
                          <label class="pm-toggle ${locked ? 'is-locked' : ''}" title="${locked ? 'ล็อก — แก้ไม่ได้' : (dirty ? 'มีการเปลี่ยนแปลง' : '')}">
                            <input type="checkbox" ${next ? 'checked' : ''} ${locked ? 'disabled' : ''} data-pm-toggle/>
                            <span class="pm-toggle-mark"></span>
                          </label>
                        </td>
                      `;
                    }).join('')}
                  </tr>
                `;
              }).join('')}
            `;
          }).join('')}
        </tbody>
      </table>
    </div>

    <div class="pm-legend">
      <span><span class="pm-legend-dot pm-legend-on"></span>เปิด</span>
      <span><span class="pm-legend-dot pm-legend-off"></span>ปิด</span>
      <span><span class="pm-legend-dot pm-legend-dirty"></span>ยังไม่บันทึก</span>
      <span>🔒 role ที่ protect</span>
      <span><span class="pm-tag pm-tag-critical">CRITICAL</span> ทุก role ต้องเปิด</span>
    </div>
  `;
}

function _wireMatrixEvents() {
  const box = document.getElementById('permMatrixBox');
  if (!box) return;

  // role CRUD buttons
  const addBtn = document.getElementById('pmAddRoleBtn');
  if (addBtn) addBtn.addEventListener('click', () => openCreateRoleModal());
  box.addEventListener('click', (e) => {
    const edit = e.target.closest('[data-pm-edit-role]');
    if (edit) { openEditRoleModal(edit.dataset.pmEditRole); return; }
    const del = e.target.closest('[data-pm-del-role]');
    if (del)  { openDeleteRoleModal(del.dataset.pmDelRole); return; }
  });

  // toggle checkbox → update draft
  box.addEventListener('change', (e) => {
    const cb = e.target.closest('[data-pm-toggle]');
    if (!cb) return;
    const cell = cb.closest('.pm-cell');
    const roleId = cell?.dataset.role;
    const permKey = cell?.dataset.perm;
    if (!roleId || !permKey) return;
    const set = _permMatrixState.draft.get(roleId) || new Set();
    if (cb.checked) set.add(permKey); else set.delete(permKey);
    _permMatrixState.draft.set(roleId, set);
    // update dirty class
    const curr = (_permMatrixState.current.get(roleId) || new Set()).has(permKey);
    cell.classList.toggle('is-dirty', curr !== cb.checked);
    _updateChangedBadge();
  });

  // collapse scope
  box.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-scope-toggle]');
    if (btn) {
      const scope = btn.dataset.scopeToggle;
      if (_permMatrixState.collapsed.has(scope)) _permMatrixState.collapsed.delete(scope);
      else _permMatrixState.collapsed.add(scope);
      // re-render เฉพาะ matrix (เก็บ search term + scroll)
      const search = document.getElementById('pmSearchInput')?.value || '';
      box.innerHTML = _renderMatrixHtml();
      _wireMatrixEvents();
      if (search) {
        const inp = document.getElementById('pmSearchInput');
        if (inp) { inp.value = search; inp.dispatchEvent(new Event('input')); }
      }
    }
  });

  // search
  const search = document.getElementById('pmSearchInput');
  if (search) {
    search.addEventListener('input', () => {
      const q = search.value.trim().toLowerCase();
      const rows = box.querySelectorAll('.pm-perm-row');
      rows.forEach(row => {
        const key = row.getAttribute('data-search') || '';
        row.style.display = (!q || key.includes(q)) ? '' : 'none';
      });
    });
  }

  // reset
  const resetBtn = document.getElementById('pmResetBtn');
  if (resetBtn) resetBtn.addEventListener('click', () => {
    if (!confirm('คืนค่ากลับเป็นที่บันทึกล่าสุด? การเปลี่ยนแปลงทั้งหมดจะหายไป')) return;
    // rebuild draft จาก current
    _permMatrixState.draft = new Map();
    for (const [roleId, set] of _permMatrixState.current) {
      _permMatrixState.draft.set(roleId, new Set(set));
    }
    // ensure ทุก role มี Set (กรณี role ไม่มี granted แม้แต่อันเดียว)
    for (const r of _permMatrixState.roles) {
      if (!_permMatrixState.draft.has(r.id)) _permMatrixState.draft.set(r.id, new Set());
    }
    box.innerHTML = _renderMatrixHtml();
    _wireMatrixEvents();
  });

  // save
  const saveBtn = document.getElementById('pmSaveBtn');
  if (saveBtn) saveBtn.addEventListener('click', async () => {
    const changed = _changedCount();
    if (!changed) return;
    if (!confirm(`บันทึก ${changed} การเปลี่ยนแปลง? — มีผลกับการใช้งานจริงทันที`)) return;
    saveBtn.disabled = true; saveBtn.textContent = 'กำลังบันทึก...';
    try {
      // หา role ที่มี diff แล้ว save ทีละตัว
      const toSave = [];
      for (const [roleId, set] of _permMatrixState.draft) {
        const orig = _permMatrixState.current.get(roleId) || new Set();
        let dirty = set.size !== orig.size;
        if (!dirty) for (const k of set) if (!orig.has(k)) { dirty = true; break; }
        if (dirty) toSave.push({ roleId, keys: Array.from(set) });
      }
      for (const { roleId, keys } of toSave) {
        await DB.setRolePermissions(roleId, keys);
      }
      toast(`บันทึก ${toSave.length} role · ${changed} การเปลี่ยนแปลง`, 'success');
      renderPermMatrix();   // reload เพื่อ sync current/draft
    } catch (ex) {
      toast('บันทึกไม่สำเร็จ: ' + (ex.message || ex), 'error');
      saveBtn.disabled = false; saveBtn.textContent = 'บันทึก';
    }
  });
}

function _updateChangedBadge() {
  const n = _changedCount();
  const stat = document.querySelector('[data-pm-changed]');
  const num = document.getElementById('pmChangedNum');
  const reset = document.getElementById('pmResetBtn');
  const save = document.getElementById('pmSaveBtn');
  if (stat) stat.style.display = n ? '' : 'none';
  if (num) num.textContent = String(n);
  if (reset) reset.disabled = !n;
  if (save) save.disabled = !n;
}

// ─── Phase 4b — Role CRUD modals ───
const BADGE_CHOICES = [
  { value: '',                label: '— ไม่มี —' },
  { value: 'badge-primary',   label: 'Primary (น้ำเงินเข้ม)' },
  { value: 'badge-success',   label: 'Success (เขียว)' },
  { value: 'badge-info',      label: 'Info (น้ำเงิน)' },
  { value: 'badge-warning',   label: 'Warning (เหลือง)' },
  { value: 'badge-danger',    label: 'Danger (แดง)' },
  { value: 'badge-gold',      label: 'Gold (champagne)' },
  { value: 'badge-neutral',   label: 'Neutral (เทา)' }
];

function openCreateRoleModal() {
  if (!DB.hasPermission('permission.edit_matrix')) {
    toast('ไม่มีสิทธิ์จัดการ role', 'error'); return;
  }
  const roles = _permMatrixState.roles || [];
  modal.open('สร้าง Role ใหม่', `
    <form id="createRoleForm">
      <div class="form-grid">
        <div class="form-group span-2">
          <label>Role ID (snake_case)</label>
          <input name="id" required pattern="^[a-z][a-z0-9_]{1,31}$" placeholder="เช่น junior_hr" autocomplete="off"/>
          <small class="muted-2" style="font-size:11px;margin-top:4px;display:block">ใช้ภายในระบบ — แก้ภายหลังไม่ได้ · ตัวอักษร a-z, 0-9, _ เริ่มด้วยตัวอักษร</small>
        </div>
        <div class="form-group span-2">
          <label>ชื่อแสดงผล (Label)</label>
          <input name="label_th" required placeholder="เช่น HR ฝึกงาน" maxlength="64"/>
        </div>
        <div class="form-group">
          <label>สี Badge</label>
          <select name="badge_class">
            ${BADGE_CHOICES.map(b => `<option value="${escapeHtml(b.value)}">${escapeHtml(b.label)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label>Clone สิทธิ์จาก Role</label>
          <select name="clone_from">
            <option value="">— ไม่ clone (role ใหม่ไม่มีสิทธิ์อะไรเลย) —</option>
            ${roles.map(r => `<option value="${escapeHtml(r.id)}">${escapeHtml(r.label_th)} (${escapeHtml(r.id)})</option>`).join('')}
          </select>
        </div>
        <div class="form-group span-2">
          <label>คำอธิบาย (ทางเลือก)</label>
          <textarea name="description" rows="2" maxlength="200" placeholder="เช่น HR ฝึกงาน — เข้าทุกหน้าได้แต่แก้ไม่ได้"></textarea>
        </div>
      </div>
    </form>
  `, {
    footer: `<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="createRoleSave">สร้าง</button>`
  });
  $('#createRoleSave').addEventListener('click', async () => {
    const form = $('#createRoleForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const data = Object.fromEntries(new FormData(form).entries());
    const btn = $('#createRoleSave'); btn.disabled = true; btn.textContent = 'กำลังสร้าง...';
    try {
      await DB.createRole({
        id: data.id.trim(),
        label_th: data.label_th.trim(),
        badge_class: data.badge_class || '',
        description: (data.description || '').trim(),
        clone_from: data.clone_from || null
      });
      modal.close();
      toast(`✓ สร้าง role "${data.label_th}" แล้ว`, 'success');
      renderPermMatrix();
    } catch (ex) {
      toast('สร้างไม่สำเร็จ: ' + (ex.message || ex), 'error');
      btn.disabled = false; btn.textContent = 'สร้าง';
    }
  });
}

function openEditRoleModal(roleId) {
  if (!DB.hasPermission('permission.edit_matrix')) {
    toast('ไม่มีสิทธิ์จัดการ role', 'error'); return;
  }
  const r = (_permMatrixState.roles || []).find(x => x.id === roleId);
  if (!r) { toast('ไม่พบ role: ' + roleId, 'error'); return; }
  modal.open(`แก้ไข Role — ${r.label_th}`, `
    <form id="editRoleForm">
      <div class="form-grid">
        <div class="form-group span-2">
          <label>Role ID</label>
          <input value="${escapeHtml(r.id)}" disabled style="background:var(--surface-2);font-family:monospace;font-size:12.5px"/>
          <small class="muted-2" style="font-size:11px;margin-top:4px;display:block">แก้ ID ไม่ได้ — ถ้าต้องการเปลี่ยน ลบและสร้างใหม่</small>
        </div>
        <div class="form-group span-2">
          <label>ชื่อแสดงผล</label>
          <input name="label_th" required value="${escapeHtml(r.label_th)}" maxlength="64"/>
        </div>
        <div class="form-group span-2">
          <label>สี Badge</label>
          <select name="badge_class">
            ${BADGE_CHOICES.map(b => `<option value="${escapeHtml(b.value)}" ${r.badge_class === b.value ? 'selected' : ''}>${escapeHtml(b.label)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group span-2">
          <label>คำอธิบาย</label>
          <textarea name="description" rows="2" maxlength="200">${escapeHtml(r.description || '')}</textarea>
        </div>
      </div>
    </form>
  `, {
    footer: `<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="editRoleSave">บันทึก</button>`
  });
  $('#editRoleSave').addEventListener('click', async () => {
    const form = $('#editRoleForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const data = Object.fromEntries(new FormData(form).entries());
    const btn = $('#editRoleSave'); btn.disabled = true; btn.textContent = 'กำลังบันทึก...';
    try {
      await DB.updateRole({
        id: roleId,
        label_th: data.label_th.trim(),
        badge_class: data.badge_class || '',
        description: (data.description || '').trim()
      });
      modal.close();
      toast('✓ แก้ไข role แล้ว', 'success');
      renderPermMatrix();
    } catch (ex) {
      toast('บันทึกไม่สำเร็จ: ' + (ex.message || ex), 'error');
      btn.disabled = false; btn.textContent = 'บันทึก';
    }
  });
}

async function openDeleteRoleModal(roleId) {
  if (!DB.hasPermission('permission.edit_matrix')) {
    toast('ไม่มีสิทธิ์จัดการ role', 'error'); return;
  }
  const r = (_permMatrixState.roles || []).find(x => x.id === roleId);
  if (!r) { toast('ไม่พบ role: ' + roleId, 'error'); return; }
  if (r.is_system) { toast('ลบ system role ไม่ได้', 'error'); return; }
  // นับ user ที่ใช้ role นี้
  const counts = await DB.getRoleUserCounts();
  const userCount = counts[roleId] || 0;
  const otherRoles = (_permMatrixState.roles || []).filter(x => x.id !== roleId);
  modal.open(`ลบ Role — ${r.label_th}`, `
    <form id="delRoleForm">
      <div style="padding:14px 16px;background:var(--danger-soft);border:1px solid rgba(196,36,63,0.3);border-radius:10px;margin-bottom:14px">
        <strong style="color:var(--danger-text)">⚠️ การลบ role นี้จะลบ permission mapping ทั้งหมดด้วย</strong>
        ${userCount > 0
          ? `<div style="margin-top:8px;font-size:13px;color:var(--text-2)">มีผู้ใช้ <strong>${userCount} คน</strong> ใช้ role นี้อยู่ — ต้องเลือก role ปลายทางเพื่อ migrate</div>`
          : `<div style="margin-top:8px;font-size:13px;color:var(--text-2)">ไม่มีผู้ใช้ที่ใช้ role นี้ — ลบได้เลย</div>`}
      </div>
      ${userCount > 0 ? `
        <div class="form-group">
          <label>ย้ายผู้ใช้ ${userCount} คนไปเป็น Role:</label>
          <select name="migrate_to" required>
            <option value="">— เลือก role ปลายทาง —</option>
            ${otherRoles.map(x => `<option value="${escapeHtml(x.id)}">${escapeHtml(x.label_th)} (${escapeHtml(x.id)})</option>`).join('')}
          </select>
        </div>
      ` : ''}
    </form>
  `, {
    footer: `<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-danger" id="delRoleConfirm">ลบ Role</button>`
  });
  $('#delRoleConfirm').addEventListener('click', async () => {
    const form = $('#delRoleForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const data = Object.fromEntries(new FormData(form).entries());
    const btn = $('#delRoleConfirm'); btn.disabled = true; btn.textContent = 'กำลังลบ...';
    try {
      const res = await DB.deleteRole(roleId, data.migrate_to || null);
      modal.close();
      const msg = res.migrated_users > 0
        ? `✓ ลบ role + ย้าย ${res.migrated_users} ผู้ใช้ → ${res.migrated_to}`
        : '✓ ลบ role แล้ว';
      toast(msg, 'success');
      renderPermMatrix();
    } catch (ex) {
      toast('ลบไม่สำเร็จ: ' + (ex.message || ex), 'error');
      btn.disabled = false; btn.textContent = 'ลบ Role';
    }
  });
}

