// ─── Employee Account Management (Settings page) ───
// Role labels + badge classes (ใช้ร่วมกัน)
const ROLE_LABELS = {
  admin:             { th: 'Admin',             badge: 'badge-primary' },
  hr:                { th: 'HR',                badge: 'badge-success' },
  operation_manager: { th: 'Operation Manager', badge: 'badge-info' },
  area_manager:      { th: 'Area Manager',      badge: 'badge-info' },
  branch_manager:    { th: 'ผู้จัดการสาขา',     badge: 'badge-warning' },
  branch_staff:      { th: 'พนักงานสาขา',       badge: '' },
  viewer:            { th: 'ผู้ใช้ทั่วไป',       badge: '' }
};

// State + actions ของ filter ในหน้า "ผู้ใช้และสิทธิ์" (รองรับพนักงานจำนวนมาก)
const _empAccFilter = { search: '', branch: '', role: '', accStatus: '' };
function setEmpAccFilter(k, v) {
  const newVal = (v ?? '').trim();
  if (_empAccFilter[k] === newVal) return;
  _empAccFilter[k] = newVal;
  renderEmpAccounts();
}
function clearEmpAccFilters() {
  _empAccFilter.search = '';
  _empAccFilter.branch = '';
  _empAccFilter.role = '';
  _empAccFilter.accStatus = '';
  renderEmpAccounts();
}

async function renderEmpAccounts() {
  const box = document.getElementById('empAccountsBox');
  if (!box || !DB.isHR) return;
  try {
    const profiles = await DB.getUserProfilesList();
    const byEmpId = new Map(profiles.filter(p => p.employee_id).map(p => [p.employee_id, p]));
    const active = DB.data.employees.filter(e => DB.empStatus(e) !== 'resigned');
    const withAcc = active.filter(e => byEmpId.has(e.id));
    const withoutAcc = active.filter(e => !byEmpId.has(e.id));
    const adminCount = Array.from(byEmpId.values()).filter(p => p.role === 'admin').length;

    // ─── Apply filters ───
    const f = _empAccFilter;
    const s = f.search.toLowerCase();
    const filtered = active.filter(e => {
      if (s) {
        const name = ((e.firstName || '') + ' ' + (e.lastName || '')).toLowerCase();
        const nick = (e.nickname || '').toLowerCase();
        const email = `${e.id.toLowerCase()}@kacha.local`;
        if (!name.includes(s) && !nick.includes(s) && !String(e.id).toLowerCase().includes(s) && !email.includes(s)) return false;
      }
      if (f.branch && e.branch !== f.branch) return false;
      const p = byEmpId.get(e.id);
      const hasAcc = !!p;
      if (f.role) {
        const roleKey = p?.role || 'viewer';
        if (f.role === 'no_account') { if (hasAcc) return false; }
        else if (roleKey !== f.role) return false;
      }
      if (f.accStatus === 'has' && !hasAcc) return false;
      if (f.accStatus === 'none' && hasAcc) return false;
      return true;
    });

    const branches = [...new Set(active.map(e => e.branch).filter(Boolean))].sort();
    const hasFilters = !!(f.search || f.branch || f.role || f.accStatus);
    const isFiltered = hasFilters;

    box.innerHTML = `
      <div class="sw-account-summary">
        <div class="sw-account-stat">
          <div class="sw-account-stat-label">มีบัญชี</div>
          <div class="sw-account-stat-value" style="color:var(--success)">${fmt.num(withAcc.length)}</div>
        </div>
        <div class="sw-account-stat">
          <div class="sw-account-stat-label">ยังไม่มี</div>
          <div class="sw-account-stat-value" style="color:${withoutAcc.length > 0 ? 'var(--warning)' : 'var(--text)'}">${fmt.num(withoutAcc.length)}</div>
        </div>
        <div class="sw-account-stat">
          <div class="sw-account-stat-label">Admin</div>
          <div class="sw-account-stat-value" style="color:var(--primary)">${fmt.num(adminCount)}</div>
        </div>
        <div class="sw-account-stat">
          <div class="sw-account-stat-label">รวม active</div>
          <div class="sw-account-stat-value">${fmt.num(active.length)}</div>
        </div>
        ${withoutAcc.length > 0 ? `<button class="btn btn-primary btn-sm" style="margin-left:auto" onclick="bulkCreateAccounts()">🚀 สร้างบัญชีให้ ${withoutAcc.length} คนที่เหลือ</button>` : ''}
      </div>

      <!-- Filter bar -->
      <div class="sw-filter-bar" style="margin-top:14px">
        <input id="empAccSearch" type="text" class="sw-filter-input" placeholder="🔍 ค้นชื่อ/รหัส/ชื่อเล่น/email"
          value="${escapeHtml(f.search)}"
          oninput="instantSearch('empAcc', this.value, v => setEmpAccFilter('search', v))"/>
        ${branches.length > 1 ? `<select class="sw-filter-select" onchange="setEmpAccFilter('branch', this.value)">
          <option value="">— ทุกสาขา —</option>
          ${branches.map(b => `<option value="${escapeHtml(b)}" ${f.branch === b ? 'selected' : ''}>${escapeHtml(b)}</option>`).join('')}
        </select>` : ''}
        <select class="sw-filter-select" onchange="setEmpAccFilter('role', this.value)">
          <option value="">— ทุก Role —</option>
          ${Object.entries(ROLE_LABELS).map(([k, v]) => `<option value="${k}" ${f.role === k ? 'selected' : ''}>${escapeHtml(v.th)}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setEmpAccFilter('accStatus', this.value)">
          <option value="">— ทุกสถานะ —</option>
          <option value="has" ${f.accStatus === 'has' ? 'selected' : ''}>✓ มีบัญชี</option>
          <option value="none" ${f.accStatus === 'none' ? 'selected' : ''}>⚠ ยังไม่มี</option>
        </select>
        ${hasFilters ? `<button class="btn btn-ghost btn-sm sw-filter-clear" onclick="clearEmpAccFilters()">✕ ล้างตัวกรอง</button>` : ''}
        ${isFiltered ? `<div class="muted-2" style="margin-left:auto;font-size:12px;align-self:center">แสดง <strong>${fmt.num(filtered.length)}</strong> / ${fmt.num(active.length)} คน</div>` : ''}
      </div>

      ${filtered.length === 0 ? `<div class="empty-state" style="padding:40px 20px;margin-top:14px">
        <div style="font-size:32px;opacity:0.3">🔍</div>
        <div class="title" style="font-size:14px;font-weight:600;margin-top:8px">ไม่พบพนักงานตามตัวกรอง</div>
        <div class="hint" style="margin-top:4px">ลองล้างตัวกรองเพื่อดูทั้งหมด</div>
      </div>` : `
      <div class="table-wrap" style="max-height:520px;overflow:auto;margin-top:14px"><table class="table table-compact sw-emp-table">
        <thead><tr><th>รหัส</th><th>ชื่อพนักงาน</th><th>สาขา</th><th>Email Login</th><th>Role</th><th>สาขาที่ดูแล</th><th>สถานะ</th><th></th></tr></thead>
        <tbody>
          ${filtered.map(e => {
            const p = byEmpId.get(e.id);
            const hasAcc = !!p;
            const email = `${e.id.toLowerCase()}@kacha.local`;
            const roleKey = p?.role || 'viewer';
            const roleInfo = ROLE_LABELS[roleKey] || ROLE_LABELS.viewer;
            const mgdBranches = Array.isArray(p?.managed_branches) ? p.managed_branches.filter(Boolean) : [];
            const showsBranches = (roleKey === 'area_manager' || roleKey === 'operation_manager');
            return `<tr>
              <td><code style="font-size:11.5px;font-weight:600">${escapeHtml(e.id)}</code></td>
              <td>
                <div class="sw-emp-cell">
                  <strong>${escapeHtml(e.firstName + ' ' + (e.lastName || ''))}</strong>
                </div>
              </td>
              <td class="sw-cell-meta">${escapeHtml(e.branch || '—')}</td>
              <td><code style="font-size:11.5px">${escapeHtml(email)}</code></td>
              <td>${hasAcc ? `<span class="badge ${roleInfo.badge}">${roleInfo.th}</span>` : '<span class="muted-2">—</span>'}</td>
              <td class="sw-cell-meta">${showsBranches ? (mgdBranches.length ? mgdBranches.map(b => `<span class="badge" style="margin-right:3px">${escapeHtml(b)}</span>`).join('') : '<span class="muted-2">(auto)</span>') : '<span class="muted-2">—</span>'}</td>
              <td>${hasAcc ? '<span class="badge badge-success">✓ มีบัญชี</span>' : '<span class="badge badge-warning">⚠️ ยังไม่มี</span>'}</td>
              <td class="actions">
                ${!hasAcc ? `<button class="btn btn-primary btn-sm" onclick="createOneAccount('${escapeHtml(e.id)}')">สร้าง</button>` : ''}
                ${hasAcc ? `<button class="btn btn-ghost btn-sm" onclick="resetEmpPassword('${escapeHtml(e.id)}')">รีเซ็ตรหัส</button>
                  <button class="btn btn-ghost btn-sm" onclick="openRoleEditor('${escapeHtml(e.id)}')">เปลี่ยน Role</button>` : ''}
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table></div>`}
    `;
  } catch (ex) {
    box.innerHTML = `<div class="empty-state" style="padding:30px 20px;color:var(--danger)">
      <div style="font-size:32px;opacity:0.5">⚠️</div>
      <div class="title" style="font-size:14px;margin-top:8px;color:var(--danger)">โหลดข้อมูลไม่สำเร็จ</div>
      <div class="hint" style="margin-top:6px">${escapeHtml(ex.message || String(ex))}</div>
    </div>`;
  }
}

// Modal เปลี่ยน role + เลือกสาขาที่ดูแล (สำหรับ Area Manager / Operation Manager)
async function openRoleEditor(empId) {
  if (!requirePermission('user.set_role', 'เปลี่ยน role พนักงาน')) return;
  const emp = DB.getEmployee(empId);
  if (!emp) return;
  const profiles = await DB.getUserProfilesList();
  const profile = profiles.find(p => p.employee_id === empId);
  const currentRole = profile?.role || 'viewer';
  const currentBranches = Array.isArray(profile?.managed_branches) ? profile.managed_branches.filter(Boolean) : [];
  const autoRole = DB.autoDetectRole(emp);
  const allBranches = DB.getBranchMaster({ activeOnly: true }) || [];

  // HR ห้ามแก้ role ของ admin คนอื่น
  if (!DB.isAdmin && currentRole === 'admin') {
    toast('HR ไม่มีสิทธิ์แก้ role ของ admin (เฉพาะ admin)', 'error');
    return;
  }

  modal.open('เปลี่ยน Role + สิทธิ์การใช้งาน',
    `<form id="roleForm">
      <div style="margin-bottom:14px;font-size:14px">
        <strong>${escapeHtml((emp.title || '') + emp.firstName + ' ' + (emp.lastName || ''))}</strong>
        <span class="muted-2" style="margin-left:8px">รหัส ${escapeHtml(emp.id)} · ${escapeHtml(emp.positionTitle || '-')}${emp.branch ? ' · ' + escapeHtml(emp.branch) : ''}</span>
      </div>
      <div class="form-group">
        <label>Role</label>
        <select name="role" id="roleSelect" required>
          ${Object.entries(ROLE_LABELS)
            .filter(([k]) => DB.isAdmin || k !== 'admin')
            .map(([k, v]) => `<option value="${k}" ${currentRole === k ? 'selected' : ''}>${v.th}</option>`).join('')}
        </select>
        ${autoRole ? `<small class="muted-2" style="display:block;margin-top:4px">💡 Auto-detect จากตำแหน่งงาน: <strong>${escapeHtml(ROLE_LABELS[autoRole]?.th || autoRole)}</strong> <button type="button" class="btn btn-ghost btn-sm" style="padding:2px 8px;margin-left:6px" onclick="document.getElementById('roleSelect').value='${escapeHtml(autoRole)}';document.getElementById('roleSelect').dispatchEvent(new Event('change'))">ใช้ค่านี้</button></small>` : ''}
        ${!DB.isAdmin ? `<small class="muted-2" style="display:block;margin-top:4px;color:var(--warning)">⚠️ HR ตั้ง role admin ไม่ได้ (เฉพาะ admin เท่านั้น)</small>` : ''}
      </div>
      <div class="form-group" id="branchesGroup" style="display:${['area_manager','operation_manager'].includes(currentRole) ? '' : 'none'}">
        <label>สาขาที่ดูแล <span class="muted-2" style="font-weight:normal;font-size:11px">(เฉพาะ Area / Operation Manager · ถ้าไม่เลือก = ใช้สาขาของตัวเอง)</span></label>
        ${renderBranchPicker({ name: 'branches', branches: allBranches, selected: currentBranches, pickerId: 'roleEditorBranchPicker' })}
        <div class="branch-picker-hint">ติ๊กสาขาที่ผู้ใช้รายนี้ได้รับมอบหมายให้กำกับดูแล — ใช้ค้นหา/เลือกทั้งหมด/ล้าง ที่แถบด้านบน</div>
      </div>
    </form>`,
    {
      footer: `<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="roleSave">บันทึก</button>`
    }
  );
  wireBranchPicker($('#branchesGroup'));
  // Toggle "สาขาที่ดูแล" ตาม role
  $('#roleSelect').addEventListener('change', (e) => {
    const v = e.target.value;
    $('#branchesGroup').style.display = (v === 'area_manager' || v === 'operation_manager') ? '' : 'none';
  });
  $('#roleSave').addEventListener('click', async () => {
    const role = $('#roleSelect').value;
    const branchInputs = $$('#roleForm input[name="branches"]:checked');
    const branches = branchInputs.map(i => i.value);
    const btn = $('#roleSave'); btn.disabled = true; btn.textContent = 'กำลังบันทึก...';
    try {
      await DB.setEmployeeRole(empId, role, ['area_manager', 'operation_manager'].includes(role) ? branches : []);
      modal.close();
      toast(`✓ เปลี่ยน role เป็น ${ROLE_LABELS[role]?.th || role}`, 'success');
      renderEmpAccounts();
    } catch (ex) {
      toast('ไม่สำเร็จ: ' + (ex.message || ex), 'error');
      btn.disabled = false; btn.textContent = 'บันทึก';
    }
  });
}

async function createOneAccount(empId) {
  if (!requirePermission('user.create_account', 'สร้างบัญชีผู้ใช้')) return;
  try {
    const res = await DB.createEmployeeAccount(empId);
    // [Security H-A3] ไม่แสดง password ใน toast — แสดง hint แทน
    toast(`✓ สำเร็จ · email: ${res.email} · password: ${res.password_hint}`, 'success');
    renderEmpAccounts();
  } catch (ex) { toast('สร้างไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
}

async function bulkCreateAccounts() {
  if (!requirePermission('user.bulk_create', 'สร้างบัญชีพร้อมกัน')) return;
  if (!await modal.confirm('สร้างบัญชีทั้งหมด', 'สร้างบัญชีให้พนักงานทุกคนที่ยังไม่มีบัญชีในระบบ?\n\nemail = {รหัส}@kacha.local\nรหัสเริ่มต้น = เลข ปชช → passport → kacha+รหัส\nrole = viewer')) return;
  try {
    const results = await DB.bulkCreateEmployeeAccounts();
    const okCount = results.filter(r => r.created).length;
    const errCount = results.filter(r => String(r.message).startsWith('ERROR')).length;
    const skipCount = results.length - okCount - errCount;
    toast(`✓ สร้าง ${okCount} ใหม่ · ข้าม ${skipCount} · ผิดพลาด ${errCount}`, errCount > 0 ? 'warning' : 'success');

    // ถ้ามี error — แสดง modal สรุปข้อผิดพลาดให้ admin ดู
    if (errCount > 0) {
      const errs = results.filter(r => String(r.message).startsWith('ERROR')).slice(0, 10);
      await modal.confirm('รายละเอียดข้อผิดพลาด', `แสดง ${errs.length} แรก:\n\n${errs.map(r => `• ${r.employee_id}: ${r.message.replace('ERROR: ', '')}`).join('\n')}`);
    }
    renderEmpAccounts();
  } catch (ex) { toast('ไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
}

async function resetEmpPassword(empId) {
  if (!requireHR()) return;
  const newPwd = await modal.prompt('รีเซ็ตรหัสผ่าน', `รหัสผ่านใหม่สำหรับ "${empId}" (เว้นว่างเพื่อรีเซ็ตเป็นเลขประชาชน):`, '');
  if (newPwd === null) return;
  try {
    const res = await DB.resetEmployeePassword(empId, newPwd.trim() || null);
    // [Security C2] reset_employee_password ไม่ return plaintext password อีกแล้ว
    // — ถ้า newPwd ว่าง → default = เลขบัตรประชาชน (ระบบรู้, HR ก็รู้ได้จากข้อมูลพนักงาน)
    const hint = newPwd.trim() ? '(ตามที่ระบุ)' : (res.password_hint || 'เลขบัตรประชาชน');
    toast(`✓ รีเซ็ตแล้ว · ระบบจะบังคับให้พนักงานเปลี่ยน password ตอน login ครั้งหน้า · default: ${hint}`, 'success');
  } catch (ex) { toast('รีเซ็ตไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
}

// toggleEmpRole() เก่า — ถูกแทนที่ด้วย openRoleEditor() (รองรับ 7 roles + managed_branches)

document.addEventListener('submit', async (e) => {
  if (e.target.id === 'companyForm') {
    e.preventDefault();
    if (!requirePermission('system.edit_company', 'แก้ไขข้อมูลบริษัท')) return;
    try {
      const data = Object.fromEntries(new FormData(e.target).entries());
      await DB.saveCompany(data);
      toast('บันทึกข้อมูลบริษัทแล้ว', 'success');
    } catch (ex) { toast('บันทึกไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
  } else if (e.target.id === 'pwForm') {
    e.preventDefault();
    const data = Object.fromEntries(new FormData(e.target).entries());
    if (data.new !== data.confirm) return toast('รหัสผ่านใหม่ไม่ตรงกัน', 'error');
    try {
      await DB.changePassword(data.new);
      toast('เปลี่ยนรหัสผ่านแล้ว', 'success');
      e.target.reset();
    } catch (ex) { toast('เปลี่ยนไม่สำเร็จ: ' + (ex.message || ex), 'error'); }
  }
});

// ═══════════════════════════════════════════════════════════
// LEAVE CALENDAR (ปฏิทินภาพรวมการลาของสาขา)
// ═══════════════════════════════════════════════════════════

const _leaveCalState = {
  month: null,     // YYYY-MM
  branchId: null,  // null = ทุกสาขา (สำหรับ HR/op_manager หรือ area_manager หลายสาขา) | string = สาขาเดียว
  _branchSet: false  // ใช้ตรวจว่า user ปรับ branchId แล้วหรือยัง
};

const LEAVE_TYPE_COLOR = {
  personal:   '#3b82f6',  // ฟ้า — ลากิจ
  sick:       '#dc2626',  // แดง — ลาป่วย
  maternity:  '#ec4899',  // ชมพู — ลาคลอด
  paternity:  '#ec4899',
  vacation:   '#16a34a',  // เขียว — พักร้อน
  ordination: '#f59e0b',  // ส้ม — บวช
  military:   '#6b7280',  // เทา — ทหาร
  _default:   '#7c3aed'
};

function leaveTypeColor(t) { return LEAVE_TYPE_COLOR[t] || LEAVE_TYPE_COLOR._default; }

function initLeaveCalState() {
  if (!_leaveCalState.month) _leaveCalState.month = tz.thisMonth();
  if (!_leaveCalState._branchSet) {
    // HR/admin/op_manager → default "ทุกสาขา" (null)
    if (DB.isHR || DB.role === 'operation_manager') {
      _leaveCalState.branchId = null;
    } else if (DB.role === 'area_manager') {
      // AM ดูแลหลายสาขา → default ทุกสาขาที่ดูแล (null), 1 สาขา → สาขานั้น
      const scoped = DB.scopedBranches() || [];
      _leaveCalState.branchId = scoped.length > 1 ? null : (scoped[0] || null);
    } else {
      _leaveCalState.branchId = DB._myBranch();
    }
    _leaveCalState._branchSet = true;
  }
}

// คืนวันแรก+สุดท้ายของเดือน + วัน weekday ของวันแรก (จันทร์=0)
function _monthInfo(yyyymm) {
  const [y, m] = yyyymm.split('-').map(Number);
  const first = new Date(y, m - 1, 1);
  const last = new Date(y, m, 0);
  const firstDow = (first.getDay() + 6) % 7;  // จันทร์=0
  return { y, m, firstDate: first, lastDate: last, firstDow, daysInMonth: last.getDate() };
}

function _addMonths(yyyymm, n) {
  const [y, m] = yyyymm.split('-').map(Number);
  const d = new Date(y, m - 1 + n, 1);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

function _formatMonthTH(yyyymm) {
  const [y, m] = yyyymm.split('-').map(Number);
  return new Date(y, m - 1, 1).toLocaleDateString('th-TH', { year: 'numeric', month: 'long' });
}

router.register('leave-calendar', () => {
  initLeaveCalState();
  const month = _leaveCalState.month;
  const branchId = _leaveCalState.branchId;
  const today = tz.today();

  const info = _monthInfo(month);
  const monthStart = `${info.y}-${String(info.m).padStart(2, '0')}-01`;
  const monthEnd = `${info.y}-${String(info.m).padStart(2, '0')}-${String(info.daysInMonth).padStart(2, '0')}`;

  // ─── สาขา options ตาม scope ───
  let branchOptions;
  let canSelectAll = false;
  if (DB.isHR || DB.role === 'operation_manager') {
    branchOptions = (DB.data.branches || []).filter(b => b.active);
    canSelectAll = true;
  } else if (DB.role === 'area_manager') {
    const scoped = DB.scopedBranches() || [];
    branchOptions = (DB.data.branches || []).filter(b => scoped.includes(b.id) && b.active);
    canSelectAll = branchOptions.length > 1;  // ดูแลหลายสาขาเท่านั้นเห็น "ทุกสาขา"
  } else {
    const scoped = DB.scopedBranches() || [];
    branchOptions = (DB.data.branches || []).filter(b => scoped.includes(b.id) && b.active);
  }
  const isAllBranches = !branchId && canSelectAll;
  const allowedBranchIds = isAllBranches
    ? branchOptions.map(b => b.id)
    : (branchId ? [branchId] : []);

  // ─── employees ของสาขาที่เลือก (active) ───
  const empsInBranch = (DB.data.employees || []).filter(e =>
    allowedBranchIds.includes(e.branch) && DB.empStatus(e) !== 'resigned'
  );
  const empIds = new Set(empsInBranch.map(e => e.id));

  // ─── leaves + swaps ที่ overlap กับเดือนนี้ ─── (เฉพาะของพนักงานในสาขา)
  // นับ approved + pending (เพื่อ planning) — ถ้า rejected/cancelled ข้าม
  const leaves = (DB.data.leaveRequests || []).filter(r =>
    empIds.has(r.employeeId)
    && (r.status === 'approved' || r.status === 'pending')
    && r.startDate <= monthEnd && r.endDate >= monthStart
  );
  const swaps = (DB.data.holidaySwapRequests || []).filter(r =>
    empIds.has(r.employeeId)
    && (r.status === 'approved' || r.status === 'pending')
    && r.swapToDate >= monthStart && r.swapToDate <= monthEnd
  );

  // map date → array of {emp, type, status, kind}
  const byDate = new Map();
  for (const lv of leaves) {
    let d = lv.startDate < monthStart ? monthStart : lv.startDate;
    const end = lv.endDate > monthEnd ? monthEnd : lv.endDate;
    while (d && d <= end) {
      if (!byDate.has(d)) byDate.set(d, []);
      byDate.get(d).push({
        kind: 'leave',
        emp: DB.getEmployee(lv.employeeId),
        leaveType: lv.leaveType,
        status: lv.status,
        ref: lv
      });
      d = addDaysYMD(d, 1);
    }
  }
  for (const sw of swaps) {
    const d = sw.swapToDate;
    if (!byDate.has(d)) byDate.set(d, []);
    byDate.get(d).push({
      kind: 'swap',
      emp: DB.getEmployee(sw.employeeId),
      status: sw.status,
      ref: sw
    });
  }

  // ─── วันหยุดประเพณีในเดือน ───
  const holidayByDate = new Map(
    (DB.data.calendar || [])
      .filter(c => c.date >= monthStart && c.date <= monthEnd)
      .map(c => [c.date, c])
  );

  // ─── สรุปวันนี้ + 7 วันข้างหน้า ───
  const todayList = byDate.get(today) || [];
  const next7End = addDaysYMD(today, 7);
  const upcomingCount = leaves.filter(lv => lv.startDate >= today && lv.startDate <= next7End).length
                      + swaps.filter(sw => sw.swapToDate >= today && sw.swapToDate <= next7End).length;
  const monthTotalLeaveDays = leaves.reduce((s, lv) => s + Number(lv.days || 0), 0);

  // ─── Build calendar grid (จันทร์-อาทิตย์) ───
  const cells = [];
  for (let i = 0; i < info.firstDow; i++) cells.push(null);  // ช่องเว้นก่อนวันที่ 1
  for (let d = 1; d <= info.daysInMonth; d++) {
    cells.push(`${info.y}-${String(info.m).padStart(2, '0')}-${String(d).padStart(2, '0')}`);
  }
  while (cells.length % 7 !== 0) cells.push(null);  // padding ท้าย

  const cellsHtml = cells.map(d => {
    if (!d) return '<div class="lcal-cell lcal-empty"></div>';
    const items = byDate.get(d) || [];
    const holiday = holidayByDate.get(d);
    const isToday = d === today;
    const isPast = d < today;
    const [yy, mm, dd] = parseYMD(d);
    const dow = (new Date(yy, mm - 1, dd).getDay() + 6) % 7;
    const isWeekend = dow >= 5;

    // dots ของแต่ละคน (max 5 dots — เหลือใส่ "+N")
    const maxDots = 5;
    const dots = items.slice(0, maxDots).map(it => {
      const color = it.kind === 'swap' ? '#0891b2' : leaveTypeColor(it.leaveType);
      const opacity = it.status === 'pending' ? 0.5 : 1;
      const branchTag = isAllBranches && it.emp?.branch ? `[${it.emp.branch}] ` : '';
      const title = `${branchTag}${it.emp?.firstName || '?'} · ${it.kind === 'swap' ? 'ชดเชย' : (DB.LEAVE_TYPES?.[it.leaveType]?.label || it.leaveType)}${it.status === 'pending' ? ' (รออนุมัติ)' : ''}`;
      return `<span class="lcal-dot" title="${escapeHtml(title)}" style="background:${color};opacity:${opacity}"></span>`;
    }).join('');
    const extra = items.length > maxDots ? `<span class="lcal-more">+${items.length - maxDots}</span>` : '';

    let cls = 'lcal-cell';
    if (isToday) cls += ' lcal-today';
    if (isPast) cls += ' lcal-past';
    if (isWeekend) cls += ' lcal-weekend';
    if (holiday) cls += ' lcal-holiday';
    if (items.length > 0) cls += ' lcal-has-leave';

    return `<div class="${cls}" onclick="openLeaveDayDetail('${escapeHtml(d)}')">
      <div class="lcal-date">${dd}</div>
      ${holiday ? `<div class="lcal-holiday-label" title="${escapeHtml(holiday.name || '')}">${escapeHtml((holiday.name || '').slice(0, 8))}</div>` : ''}
      <div class="lcal-dots">${dots}${extra}</div>
      ${items.length > 0 ? `<div class="lcal-count">${items.length} คน</div>` : ''}
    </div>`;
  }).join('');

  const dayHeaderHtml = ['จันทร์','อังคาร','พุธ','พฤหัสบดี','ศุกร์','เสาร์','อาทิตย์']
    .map((n, i) => `<div class="lcal-day-name ${i >= 5 ? 'lcal-weekend' : ''}">${n}</div>`).join('');

  // ─── Today summary list ───
  const todayHtml = todayList.length === 0
    ? `<div class="lcal-empty-today">${icon('party', { size: 24 })} <span>ไม่มีพนักงานลาวันนี้ — ครบทุกคน</span></div>`
    : todayList.map(it => {
        const color = it.kind === 'swap' ? '#0891b2' : leaveTypeColor(it.leaveType);
        const typeLabel = it.kind === 'swap' ? 'ชดเชยวันหยุดประเพณี' : (DB.LEAVE_TYPES?.[it.leaveType]?.label || it.leaveType);
        return `<div class="lcal-today-item">
          <span class="lcal-dot lcal-dot-lg" style="background:${color};opacity:${it.status === 'pending' ? 0.5 : 1}"></span>
          <div class="lcal-today-info">
            <div>
              ${isAllBranches && it.emp?.branch ? `<span class="badge" style="font-size:10px;margin-right:4px">${escapeHtml(it.emp.branch)}</span>` : ''}
              <strong>${escapeHtml((it.emp?.firstName || '?') + ' ' + (it.emp?.lastName || ''))}</strong>
              ${it.emp?.nickname ? `<span class="muted-2">(${escapeHtml(it.emp.nickname)})</span>` : ''}
            </div>
            <div class="muted-2" style="font-size:11px">${escapeHtml(it.emp?.id || '')} · ${escapeHtml(typeLabel)}${it.status === 'pending' ? ' · <span class="badge badge-warning" style="font-size:9px">รออนุมัติ</span>' : ''}</div>
          </div>
        </div>`;
      }).join('');

  return `
    <div class="sw-page-header">
      <div>
        <div class="sw-page-title">ปฏิทินสาขา · ภาพรวมการลา</div>
        <div class="sw-page-subtitle">ดูพนักงานที่ลาในแต่ละวัน — บริหารกะ + หาคนแทนได้ทันเวลา</div>
      </div>
    </div>

    <div class="sw-stats-grid" style="margin-bottom:18px">
      <div class="sw-stat-card">
        <div class="sw-stat-icon" style="background:rgba(59,130,246,0.12);color:#3b82f6">${icon('calendar', { size: 22 })}</div>
        <div class="sw-stat-label">วันนี้</div>
        <div class="sw-stat-value" style="color:${todayList.length > 0 ? '#dc2626' : 'var(--success)'}">${fmt.num(todayList.length)}</div>
        <div class="sw-stat-change muted-2" style="font-size:12px;margin-top:6px">${todayList.length > 0 ? 'พนักงานลาวันนี้' : 'ครบทุกคน'}</div>
      </div>
      <div class="sw-stat-card">
        <div class="sw-stat-icon" style="background:rgba(234,179,8,0.12);color:#eab308">${icon('clock', { size: 22 })}</div>
        <div class="sw-stat-label">7 วันข้างหน้า</div>
        <div class="sw-stat-value">${fmt.num(upcomingCount)}</div>
        <div class="sw-stat-change muted-2" style="font-size:12px;margin-top:6px">รายการลา/swap ที่กำลังมา</div>
      </div>
      <div class="sw-stat-card">
        <div class="sw-stat-icon" style="background:rgba(124,58,237,0.12);color:#7c3aed">${icon('chart', { size: 22 })}</div>
        <div class="sw-stat-label">รวมเดือน ${_formatMonthTH(month)}</div>
        <div class="sw-stat-value">${fmt.num(monthTotalLeaveDays)}</div>
        <div class="sw-stat-change muted-2" style="font-size:12px;margin-top:6px">วัน-คน ที่ลาใน${isAllBranches ? `${allowedBranchIds.length} สาขา` : 'สาขานี้'}</div>
      </div>
      <div class="sw-stat-card">
        <div class="sw-stat-icon" style="background:rgba(22,163,74,0.12);color:var(--success)">${icon('users', { size: 22 })}</div>
        <div class="sw-stat-label">${isAllBranches ? 'พนักงานทุกสาขา' : 'พนักงานสาขา'}</div>
        <div class="sw-stat-value">${fmt.num(empsInBranch.length)}</div>
        <div class="sw-stat-change muted-2" style="font-size:12px;margin-top:6px">active${isAllBranches ? ` · ${allowedBranchIds.length} สาขา` : ' ในสาขานี้'}</div>
      </div>
    </div>

    <div class="sw-chart-card" style="margin-bottom:16px">
      <div class="lcal-controls">
        <div class="lcal-month-nav">
          <button class="btn btn-ghost btn-icon-only" onclick="navLeaveCalMonth(-1)" title="เดือนก่อน">◀</button>
          <button class="btn btn-secondary" onclick="navLeaveCalToday()">เดือนนี้</button>
          <button class="btn btn-ghost btn-icon-only" onclick="navLeaveCalMonth(1)" title="เดือนถัดไป">▶</button>
          <div class="lcal-month-label">${_formatMonthTH(month)}</div>
        </div>
        <div style="flex:1"></div>
        <select class="sw-filter-select" onchange="setLeaveCalBranch(this.value)" ${(branchOptions.length === 1 && !canSelectAll) ? 'disabled' : ''}>
          ${branchOptions.length === 0 ? '<option value="">— ไม่มีสาขา —</option>' : ''}
          ${canSelectAll ? `<option value="" ${isAllBranches ? 'selected' : ''}>📊 ทุกสาขา (${branchOptions.length} สาขา)</option>` : ''}
          ${branchOptions.map(b => `<option value="${escapeHtml(b.id)}" ${branchId === b.id ? 'selected' : ''} title="${escapeHtml(b.name || '')}">${escapeHtml(b.id)}</option>`).join('')}
        </select>
      </div>
      <div class="lcal-legend">
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#3b82f6"></span> ลากิจ</span>
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#dc2626"></span> ลาป่วย</span>
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#16a34a"></span> พักร้อน</span>
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#ec4899"></span> ลาคลอด</span>
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#f59e0b"></span> บวช</span>
        <span class="lcal-legend-item"><span class="lcal-dot" style="background:#0891b2"></span> ชดเชย</span>
        <span class="lcal-legend-item muted-2" style="margin-left:auto">จุดทึบ = อนุมัติ · จุดจาง = รออนุมัติ</span>
      </div>
    </div>

    <div class="sw-chart-card lcal-card">
      <div class="lcal-week-head">${dayHeaderHtml}</div>
      <div class="lcal-grid">${cellsHtml}</div>
    </div>

    <div class="sw-chart-card" style="margin-top:16px">
      <div class="sw-chart-header">
        <div>
          <div class="sw-chart-title">วันนี้มีใครลาบ้าง <span class="sw-chart-count">${fmt.num(todayList.length)}</span></div>
          <div class="sw-chart-sub">${escapeHtml(new Date().toLocaleDateString('th-TH', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }))}</div>
        </div>
      </div>
      <div class="lcal-today-list">${todayHtml}</div>
    </div>
  `;
});

function navLeaveCalMonth(delta) {
  _leaveCalState.month = _addMonths(_leaveCalState.month, delta);
  router.go('leave-calendar');
}
function navLeaveCalToday() {
  _leaveCalState.month = tz.thisMonth();
  router.go('leave-calendar');
}
function setLeaveCalBranch(branchId) {
  _leaveCalState.branchId = branchId || null;  // '' → null = ทุกสาขา
  _leaveCalState._branchSet = true;
  router.go('leave-calendar');
}

// Modal — รายละเอียดวันที่เลือก
function openLeaveDayDetail(dateStr) {
  const branchId = _leaveCalState.branchId;
  const [y, m, d] = parseYMD(dateStr);
  const dayLabel = new Date(y, m - 1, d).toLocaleDateString('th-TH', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

  // คำนวณ allowed branches แบบเดียวกับ render
  let allowed;
  if (branchId) {
    allowed = [branchId];
  } else {
    // ทุกสาขาตาม scope
    if (DB.isHR || DB.role === 'operation_manager') {
      allowed = (DB.data.branches || []).filter(b => b.active).map(b => b.id);
    } else {
      allowed = DB.scopedBranches() || [];
    }
  }
  const empIds = new Set((DB.data.employees || []).filter(e => allowed.includes(e.branch)).map(e => e.id));
  const leaves = (DB.data.leaveRequests || []).filter(r =>
    empIds.has(r.employeeId)
    && (r.status === 'approved' || r.status === 'pending')
    && r.startDate <= dateStr && r.endDate >= dateStr
  );
  const swaps = (DB.data.holidaySwapRequests || []).filter(r =>
    empIds.has(r.employeeId)
    && (r.status === 'approved' || r.status === 'pending')
    && r.swapToDate === dateStr
  );
  const holiday = (DB.data.calendar || []).find(c => c.date === dateStr);

  const items = [
    ...leaves.map(lv => ({ kind: 'leave', ref: lv, emp: DB.getEmployee(lv.employeeId) })),
    ...swaps.map(sw => ({ kind: 'swap', ref: sw, emp: DB.getEmployee(sw.employeeId) }))
  ];

  const body = items.length === 0
    ? `<div class="empty-state" style="padding:30px"><div style="color:var(--success);margin-bottom:8px">${icon('party', { size: 40 })}</div><div class="title">ไม่มีพนักงานลาวันนี้</div></div>`
    : `<div class="lcal-modal-list">
        ${items.map(it => {
          const e = it.emp || {};
          const isLeave = it.kind === 'leave';
          const typeLabel = isLeave
            ? (DB.LEAVE_TYPES?.[it.ref.leaveType]?.label || it.ref.leaveType)
            : 'ชดเชยวันหยุดประเพณี';
          const color = isLeave ? leaveTypeColor(it.ref.leaveType) : '#0891b2';
          const range = isLeave
            ? (it.ref.startDate === it.ref.endDate
                ? fmt.date(it.ref.startDate)
                : `${fmt.date(it.ref.startDate)} – ${fmt.date(it.ref.endDate)}`)
            : `วันที่ชดเชย ${fmt.date(it.ref.swapToDate)}`;
          return `<div class="lcal-modal-item">
            <span class="lcal-dot lcal-dot-lg" style="background:${color}"></span>
            <div style="flex:1">
              <div>
                ${e.branch ? `<span class="badge" style="font-size:10px;margin-right:4px">${escapeHtml(e.branch)}</span>` : ''}
                <strong>${escapeHtml((e.firstName || '?') + ' ' + (e.lastName || ''))}</strong>
                ${e.nickname ? `<span class="muted-2">(${escapeHtml(e.nickname)})</span>` : ''}
                <span class="muted-2" style="font-size:11px;margin-left:4px">${escapeHtml(e.id || '')}</span>
              </div>
              <div class="muted-2" style="font-size:12px">
                ${escapeHtml(typeLabel)} · ${escapeHtml(range)}
                ${isLeave && it.ref.days ? ` · ${it.ref.days} วัน` : ''}
                ${it.ref.status === 'pending' ? ' · <span class="badge badge-warning" style="font-size:10px">รออนุมัติ</span>' : ' · <span class="badge badge-success" style="font-size:10px">อนุมัติ</span>'}
              </div>
              ${it.ref.reason ? `<div class="muted-2" style="font-size:11px;font-style:italic;margin-top:2px">"${escapeHtml(it.ref.reason)}"</div>` : ''}
            </div>
          </div>`;
        }).join('')}
      </div>`;

  const title = `${holiday ? '🎉 ' + holiday.name + ' — ' : ''}${dayLabel} (${items.length} คน)`;
  modal.open(title, body, {
    footer: '<button class="btn btn-secondary" data-close>ปิด</button>'
  });
}

// ═══════════════════════════════════════════════════════════
// WORK SCHEDULE (ตารางงานพนักงาน) — กะรายสัปดาห์ + อนุมัติ
// ═══════════════════════════════════════════════════════════

const _scheduleState = {
  weekStart: null,   // YYYY-MM-DD ของวันจันทร์
  branchId: null     // สาขาที่กำลังดู
};

const SCHEDULE_STATUS_BADGE = {
  draft:     { label: 'แบบร่าง',    cls: 'badge' },
  submitted: { label: 'รออนุมัติ',  cls: 'badge-warning' },
  approved:  { label: 'อนุมัติแล้ว', cls: 'badge-success' },
  rejected:  { label: 'ปฏิเสธ',     cls: 'badge-danger' }
};

const DOW_LABELS_TH    = ['จันทร์', 'อังคาร', 'พุธ', 'พฤหัสบดี', 'ศุกร์', 'เสาร์', 'อาทิตย์'];
const DOW_LABELS_SHORT = ['จ', 'อ', 'พ', 'พฤ', 'ศ', 'ส', 'อา'];

// คืนวันจันทร์ของสัปดาห์ที่ ymd อยู่ (ISO — จันทร์เป็นวันแรก)
function getMondayOf(ymd) {
  const p = parseYMD(ymd);
  if (!p) return null;
  const d = new Date(p[0], p[1] - 1, p[2]);
  const dow = d.getDay() || 7;
  d.setDate(d.getDate() - (dow - 1));
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

function addDaysYMD(ymd, n) {
  const p = parseYMD(ymd);
  if (!p) return ymd;
  const d = new Date(p[0], p[1] - 1, p[2]);
  d.setDate(d.getDate() + n);
  const pad = (k) => String(k).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

function formatWeekRange(monday) {
  const sunday = addDaysYMD(monday, 6);
  return `${fmt.date(monday)} – ${fmt.date(sunday)}`;
}

function initScheduleStateIfNeeded() {
  if (!_scheduleState.weekStart) {
    _scheduleState.weekStart = getMondayOf(tz.today());
  }
  // [Cleanup] '__all__' ถูกลบออกจาก dropdown แล้ว (ซ้ำกับปุ่ม "ภาพรวมทุกสาขา")
  // — reset state ที่ค้างจาก session เก่า เพื่อไม่ให้ render summary ที่ไม่มีทางออก
  if (_scheduleState.branchId === '__all__') _scheduleState.branchId = null;
  if (!_scheduleState.branchId) {
    if (DB.role === 'branch_manager' || DB.role === 'area_manager' || DB.role === 'branch_staff' || DB.role === 'viewer') {
      _scheduleState.branchId = DB._myBranch();
    }
    if (!_scheduleState.branchId) {
      const branches = (DB.data.branches || []).filter(b => b.active);
      _scheduleState.branchId = branches[0]?.id || null;
    }
  }
}

// ═══════════════════════════════════════════════════════════
// CROSS-BRANCH BORROW REQUESTS (Phase 3 Level 3) — หน้า "ขอยืมพนักงาน"
// ═══════════════════════════════════════════════════════════
const BORROW_STATUS_BADGE = {
  pending:   { label: '⏳ รออนุมัติ',     cls: 'badge-warning' },
  approved:  { label: '✓ อนุมัติแล้ว',   cls: 'badge-success' },
  rejected:  { label: '✕ ปฏิเสธ',         cls: 'badge-danger' },
  cancelled: { label: '⊘ ยกเลิก',          cls: 'badge' }
};
// แสดง badge เพิ่ม "Auto" ถ้า auto_approved = true
function _borrowBadgeHtml(r) {
  const base = BORROW_STATUS_BADGE[r.status] || { label: r.status, cls: 'badge' };
  let html = `<span class="badge ${base.cls}">${escapeHtml(base.label)}</span>`;
  if (r.autoApproved) {
    html += `<br><span class="badge" style="font-size:10px;margin-top:2px;background:rgba(34,197,94,0.12);color:var(--success);border:1px solid rgba(34,197,94,0.3)" title="ระบบอนุมัติอัตโนมัติ เพราะผู้สร้างคำขอมีสิทธิ์ดูแลทั้ง 2 สาขา">⚡ Auto</span>`;
  }
  return html;
}

function fmtWorkDates(arr) {
  if (!Array.isArray(arr) || !arr.length) return '-';
  if (arr.length === 1) return fmt.date(arr[0]);
  if (arr.length <= 3) return arr.map(d => fmt.date(d)).join(', ');
  return `${fmt.date(arr[0])} … ${fmt.date(arr[arr.length-1])} (${arr.length} วัน)`;
}

router.register('borrow-requests', () => {
  const list = DB.data.borrowRequests || [];
  const role = DB.role;
  const myId = DB.profile?.employee_id;
  const pendingForMe = list.filter(r => r.status === 'pending');
  const totalPending = pendingForMe.length;

  return `
    <div class="sw-page-title">ขอยืมพนักงานข้ามสาขา</div>
    <div class="sw-page-subtitle">
      เมื่อต้องการให้พนักงานสาขาอื่นมาช่วยตารางงาน — ต้องขอ AM ของสาขาแม่อนุมัติก่อน
    </div>

    <div class="card mt-4">
      <div class="flex items-center" style="justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:14px">
        <div style="display:flex;gap:10px;flex-wrap:wrap">
          <span class="badge badge-warning" style="font-size:13px;padding:6px 12px">⏳ รออนุมัติ ${totalPending}</span>
          <span class="badge" style="font-size:13px;padding:6px 12px">รวมทั้งหมด ${list.length}</span>
        </div>
        <button class="btn btn-primary" onclick="openBorrowRequestForm()">+ สร้างคำขอใหม่</button>
      </div>

      ${list.length === 0 ? `
        <div class="empty-state" style="padding:32px">
          <div class="icon">👥</div>
          <div>ยังไม่มีคำขอยืมพนักงาน</div>
          <div class="muted-2" style="font-size:13px;margin-top:6px">กด "+ สร้างคำขอใหม่" เมื่อต้องการดึงพนักงานสาขาอื่นมาช่วย</div>
        </div>
      ` : `
        <div class="table-wrap">
          <table class="table" style="font-size:13px">
            <thead><tr>
              <th>สถานะ</th>
              <th>พนักงาน</th>
              <th>สาขาแม่ → ปลายทาง</th>
              <th>วันที่ขอยืม</th>
              <th>เหตุผล</th>
              <th>หมายเหตุ</th>
              <th>การกระทำ</th>
            </tr></thead>
            <tbody>
              ${list.map(r => {
                const emp = DB.getEmployee(r.employeeId);
                const empName = emp ? `${emp.firstName || ''} ${emp.lastName || ''}`.trim() : r.employeeId;
                const note = r.status === 'rejected' ? r.rejectReason : (r.status === 'approved' ? r.approverNote : (r.status === 'cancelled' ? r.cancelReason : ''));
                // ใครเห็นปุ่มอนุมัติ/ปฏิเสธ?
                const canReview = r.status === 'pending' && (
                  DB.isHR ||
                  (role === 'area_manager' && (DB._managedBranches || []).includes(r.sourceBranchId)) ||
                  (role === 'operation_manager')
                );
                const canCancel = ['pending', 'approved'].includes(r.status) && (
                  DB.isHR ||
                  r.requestedBy === DB.user?.id
                );
                return `<tr>
                  <td>${_borrowBadgeHtml(r)}</td>
                  <td><strong>${escapeHtml(r.employeeId)}</strong><br>
                    <span class="muted-2" style="font-size:12px">${escapeHtml(empName)}</span></td>
                  <td>
                    <code>${escapeHtml(r.sourceBranchId)}</code>
                    <span class="muted-2"> → </span>
                    <code>${escapeHtml(r.destinationBranchId)}</code>
                  </td>
                  <td style="font-size:12px">${escapeHtml(fmtWorkDates(r.workDates))}</td>
                  <td style="max-width:240px;word-break:break-word">${escapeHtml(r.reason || '-')}</td>
                  <td style="max-width:200px;word-break:break-word;font-size:12px">${escapeHtml(note || '-')}</td>
                  <td>
                    ${canReview ? `
                      <button class="btn btn-success btn-sm" onclick="reviewBorrowUI('${escapeHtml(r.id)}', 'approved')">✓ อนุมัติ</button>
                      <button class="btn btn-danger btn-sm" onclick="reviewBorrowUI('${escapeHtml(r.id)}', 'rejected')">✕ ปฏิเสธ</button>
                    ` : ''}
                    ${canCancel ? `
                      <button class="btn btn-ghost btn-sm" onclick="cancelBorrowUI('${escapeHtml(r.id)}')">ยกเลิก</button>
                    ` : ''}
                  </td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      `}
    </div>
  `;
});

async function openBorrowRequestForm(preset = {}) {
  if (!DB.canCreateScheduleForBranch && typeof DB.canCreateScheduleForBranch !== 'function') {
    if (!DB.isHR && DB.role !== 'branch_manager' && DB.role !== 'operation_manager') {
      toast('ต้องเป็น Branch Manager / HR / admin', 'error');
      return;
    }
  }
  const presetBranch = preset.destBranch || '';
  const presetEmpId = preset.employeeId || '';
  const presetDates = Array.isArray(preset.workDates) ? preset.workDates : [];
  const branches = DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : [];
  // default วันแรก = วันถัดไป (พรุ่งนี้)
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowStr = tomorrow.toLocaleDateString('en-CA', { timeZone: 'Asia/Bangkok' });

  modal.open('สร้างคำขอยืมพนักงาน', `
    <form id="borrowReqForm" class="form-grid">
      <div class="form-group span-2">
        <label>สาขาปลายทาง (ที่จะใช้พนักงาน) *</label>
        <select name="destBranch" required>
          <option value="">— เลือกสาขา —</option>
          ${branches.map(b => `<option value="${escapeHtml(b.id)}" title="${escapeHtml(b.name || '')}" ${b.id === presetBranch ? 'selected' : ''}>${escapeHtml(b.id)}</option>`).join('')}
        </select>
      </div>
      <div class="form-group span-2">
        <label>พนักงานที่ต้องการยืม (รหัส) *</label>
        <input name="employeeId" required placeholder="เช่น 65010" autocomplete="off" value="${escapeHtml(presetEmpId)}"/>
        <small class="muted-2" style="font-size:11px;margin-top:4px;display:block">ระบบจะตรวจสาขาแม่ของพนักงานอัตโนมัติ — ถ้าสาขาแม่ตรงกับปลายทาง จะปฏิเสธ</small>
      </div>
      <div class="form-group span-2">
        <label>วันทำงานที่ต้องการ (เลือกได้หลายวัน) *</label>
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:8px">
          <input type="date" id="borrowDateInput" value="${tomorrowStr}" min="${tomorrowStr.slice(0,10)}" style="flex:1"/>
          <button type="button" class="btn btn-secondary btn-sm" id="borrowDateAdd">+ เพิ่ม</button>
        </div>
        <!-- Quick presets -->
        <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:8px">
          <button type="button" class="btn btn-ghost btn-sm" data-preset="weekend" style="font-size:11.5px;padding:3px 10px">เสาร์-อาทิตย์</button>
          <button type="button" class="btn btn-ghost btn-sm" data-preset="next7" style="font-size:11.5px;padding:3px 10px">7 วันถัดไป</button>
          <button type="button" class="btn btn-ghost btn-sm" data-preset="weekdays" style="font-size:11.5px;padding:3px 10px">จันทร์-ศุกร์ สัปดาห์หน้า</button>
          <button type="button" class="btn btn-ghost btn-sm" id="borrowDateClear" style="font-size:11.5px;padding:3px 10px;color:var(--danger)">ล้างทั้งหมด</button>
        </div>
        <!-- Selected chips -->
        <div id="borrowDateChips" style="display:flex;gap:6px;flex-wrap:wrap;min-height:36px;padding:8px;background:var(--surface-2);border-radius:8px;border:1px dashed var(--border)">
          <span class="muted-2" id="borrowDateEmpty" style="font-size:12px;align-self:center">ยังไม่ได้เลือกวัน — ใช้ปุ่ม "+ เพิ่ม" หรือกดปุ่มลัดด้านบน</span>
        </div>
        <small class="muted-2" style="font-size:11px;margin-top:4px;display:block">สูงสุด 14 วันต่อคำขอ — คลิก × ที่แต่ละวันเพื่อเอาออก</small>
      </div>
      <div class="form-group span-2">
        <label>เหตุผลที่ขอยืม</label>
        <textarea name="reason" rows="3" placeholder="เช่น พนักงานสาขาเราลาเร่งด่วน 2 คน — ต้องการคนช่วยช่วงเทศกาล"></textarea>
      </div>
    </form>
  `, {
    size: 'sm',
    footer: '<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="borrowReqSubmit">ส่งคำขอ</button>'
  });

  // ─── Multi-date picker logic ───
  const selectedDates = new Set(presetDates.filter(d => /^\d{4}-\d{2}-\d{2}$/.test(d)));
  const renderChips = () => {
    const wrap = document.getElementById('borrowDateChips');
    const empty = document.getElementById('borrowDateEmpty');
    if (!wrap) return;
    if (selectedDates.size === 0) {
      wrap.innerHTML = '<span class="muted-2" id="borrowDateEmpty" style="font-size:12px;align-self:center">ยังไม่ได้เลือกวัน — ใช้ปุ่ม "+ เพิ่ม" หรือกดปุ่มลัดด้านบน</span>';
      return;
    }
    const sorted = [...selectedDates].sort();
    wrap.innerHTML = sorted.map(d => `
      <span style="display:inline-flex;align-items:center;gap:6px;padding:4px 8px;background:var(--surface);border:1px solid var(--border);border-radius:6px;font-size:12.5px">
        ${escapeHtml(fmt.date(d))}
        <button type="button" data-remove-date="${escapeHtml(d)}" style="background:none;border:none;color:var(--danger);cursor:pointer;font-size:14px;padding:0;line-height:1" title="เอาออก">×</button>
      </span>
    `).join('');
    // wire remove buttons
    wrap.querySelectorAll('[data-remove-date]').forEach(btn => {
      btn.addEventListener('click', () => {
        selectedDates.delete(btn.dataset.removeDate);
        renderChips();
      });
    });
  };
  const addDate = (d) => {
    if (!d || !/^\d{4}-\d{2}-\d{2}$/.test(d)) return;
    if (selectedDates.size >= 14) {
      toast('สูงสุด 14 วันต่อคำขอ', 'warning');
      return;
    }
    selectedDates.add(d);
    renderChips();
  };
  // ถ้า preset มาก่อน → render chips ครั้งแรก
  if (selectedDates.size > 0) renderChips();
  document.getElementById('borrowDateAdd').addEventListener('click', () => {
    const inp = document.getElementById('borrowDateInput');
    if (inp.value) {
      addDate(inp.value);
      // เลื่อนวันถัดไปอัตโนมัติเพื่อกดเร็วๆ
      const nx = new Date(inp.value + 'T00:00:00');
      nx.setDate(nx.getDate() + 1);
      inp.value = nx.toLocaleDateString('en-CA');
    }
  });
  document.getElementById('borrowDateClear').addEventListener('click', () => {
    selectedDates.clear();
    renderChips();
  });
  // Quick presets
  document.querySelectorAll('[data-preset]').forEach(btn => {
    btn.addEventListener('click', () => {
      const preset = btn.dataset.preset;
      const today = new Date();
      today.setHours(0,0,0,0);
      if (preset === 'weekend') {
        // เสาร์-อาทิตย์ที่ใกล้สุดในอนาคต
        const dow = today.getDay();   // 0=Sun, 6=Sat
        const daysToSat = (6 - dow + 7) % 7 || 7;
        const sat = new Date(today); sat.setDate(today.getDate() + daysToSat);
        const sun = new Date(sat); sun.setDate(sat.getDate() + 1);
        addDate(sat.toLocaleDateString('en-CA'));
        addDate(sun.toLocaleDateString('en-CA'));
      } else if (preset === 'next7') {
        for (let i = 1; i <= 7; i++) {
          const d = new Date(today); d.setDate(today.getDate() + i);
          addDate(d.toLocaleDateString('en-CA'));
        }
      } else if (preset === 'weekdays') {
        // จันทร์-ศุกร์ของสัปดาห์หน้า
        const dow = today.getDay();
        const daysToMon = (1 - dow + 7) % 7 || 7;
        for (let i = 0; i < 5; i++) {
          const d = new Date(today); d.setDate(today.getDate() + daysToMon + i);
          addDate(d.toLocaleDateString('en-CA'));
        }
      }
    });
  });

  $('#borrowReqSubmit').addEventListener('click', async () => {
    const form = $('#borrowReqForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const fd = new FormData(form);
    const destBranch = (fd.get('destBranch') || '').toString().trim();
    const employeeId = (fd.get('employeeId') || '').toString().trim();
    const reason = (fd.get('reason') || '').toString().trim();
    const workDates = [...selectedDates].sort();
    if (workDates.length === 0) {
      toast('ต้องเลือกวันทำงานอย่างน้อย 1 วัน', 'error');
      return;
    }
    const btn = $('#borrowReqSubmit'); btn.disabled = true; btn.textContent = 'กำลังส่ง...';
    try {
      const result = await DB.createBorrowRequest({ employeeId, destinationBranchId: destBranch, workDates, reason });
      modal.close();
      // ★ RPC คืน auto_approved → แสดง toast ต่างกัน
      if (result && result.auto_approved) {
        toast('⚡ อนุมัติอัตโนมัติ — ใส่กะให้พนักงานได้ทันที (คุณมีสิทธิ์ดูแลทั้ง 2 สาขา)', 'success');
      } else {
        toast('✓ ส่งคำขอแล้ว — รอ AM สาขาแม่อนุมัติ', 'success');
      }
      router.go('borrow-requests');
    } catch (ex) {
      toast(ex.message || String(ex), 'error');
      btn.disabled = false; btn.textContent = 'ส่งคำขอ';
    }
  });
}

async function reviewBorrowUI(requestId, decision) {
  const action = decision === 'approved' ? 'อนุมัติ' : 'ปฏิเสธ';
  const note = await modal.prompt(`${action}คำขอยืมพนักงาน`, `กรอกหมายเหตุ (ทางเลือก):`, '');
  if (note === null) return;
  try {
    await DB.reviewBorrowRequest(requestId, decision, note);
    toast(`✓ ${action}คำขอแล้ว`, 'success');
    router.go('borrow-requests');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

async function cancelBorrowUI(requestId) {
  const reason = await modal.prompt('ยกเลิกคำขอยืม', 'เหตุผลที่ยกเลิก (ทางเลือก):', '');
  if (reason === null) return;
  try {
    await DB.cancelBorrowRequest(requestId, reason);
    toast('ยกเลิกคำขอแล้ว', 'success');
    router.go('borrow-requests');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

// Badge: นับคำขอที่ user คนนี้ต้อง review (rolling)
function updateBorrowBadge() {
  const badge = document.getElementById('navBadgeBorrow');
  if (!badge) return;
  const list = DB.data.borrowRequests || [];
  // ถ้าเป็น HR — นับทั้งหมด, ถ้าเป็น AM/OM — นับเฉพาะ source ที่ตัวเองดูแล
  let pending = 0;
  if (DB.isHR) {
    pending = list.filter(r => r.status === 'pending').length;
  } else if (DB.role === 'area_manager' || DB.role === 'operation_manager') {
    const managed = DB._managedBranches || [];
    pending = list.filter(r => r.status === 'pending' && managed.includes(r.sourceBranchId)).length;
  }
  if (pending > 0) {
    badge.textContent = String(pending);
    badge.style.display = 'inline-block';
    badge.title = `${pending} คำขอยืมพนักงานรออนุมัติ`;
  } else {
    badge.style.display = 'none';
  }
}

// ═══════════════════════════════════════════════════════════
// HEADCOUNT REQUESTS — หน้า "ขออัตรากำลัง" (BM → AM → HR)
// ═══════════════════════════════════════════════════════════
const HC_STATUS_BADGE = {
  pending_am: { label: '⏳ รอ AM อนุมัติ',  cls: 'badge-warning' },
  pending_hr: { label: '⏳ รอ HR อนุมัติ',  cls: 'badge-warning' },
  approved:   { label: '✓ อนุมัติแล้ว',     cls: 'badge-success' },
  fulfilled:  { label: '🎯 เติมอัตราแล้ว',   cls: 'badge-success' },
  rejected:   { label: '✕ ปฏิเสธ',           cls: 'badge-danger' },
  cancelled:  { label: '⊘ ยกเลิก',            cls: 'badge' }
};
function _hcBadgeHtml(r) {
  const base = HC_STATUS_BADGE[r.status] || { label: r.status, cls: 'badge' };
  let html = `<span class="badge ${base.cls}">${escapeHtml(base.label)}</span>`;
  if (r.status === 'rejected' && r.rejectedByRole) {
    html += `<br><span class="muted-2" style="font-size:10.5px">โดย ${r.rejectedByRole === 'hr' ? 'HR' : 'AM'}</span>`;
  }
  return html;
}

const _hcFilter = { year: '', status: '' };
function setHcFilter(k, v) { _hcFilter[k] = v || ''; router.go('headcount'); }
function clearHcFilter() { _hcFilter.year = ''; _hcFilter.status = ''; router.go('headcount'); }

router.register('headcount', () => {
  const allList = DB.getHeadcountRequests();
  const role = DB.role;
  // ─── ตัวกรอง: ปี (จากวันที่ขอ) + สถานะ — ดูย้อนหลังได้ ───
  const list = allList.filter(r => {
    if (_hcFilter.year && String(r.requestedAt || '').slice(0, 4) !== _hcFilter.year) return false;
    if (_hcFilter.status && r.status !== _hcFilter.status) return false;
    return true;
  });
  const _hcHasFilter = !!(_hcFilter.year || _hcFilter.status);
  const _hcYears = (() => {
    const ty = new Date().getFullYear();
    const ys = new Set(allList.map(r => String(r.requestedAt || '').slice(0, 4)).filter(Boolean));
    for (let y = ty - 5; y <= ty; y++) ys.add(String(y));
    return Array.from(ys).filter(Boolean).sort((a, b) => Number(b) - Number(a));
  })();
  // ใครอนุมัติคำขอนี้ได้ (ตาม step): pending_am → AM ของสาขา/HR ; pending_hr → HR
  const canActOn = (r) => {
    if (r.status === 'pending_am') return DB.isHR || ((role === 'area_manager' || role === 'operation_manager') && (DB._managedBranches || []).includes(r.branchId));
    if (r.status === 'pending_hr') return DB.isHR;
    return false;
  };
  const totalPending = allList.filter(r => r.status === 'pending_am' || r.status === 'pending_hr').length;
  const canCreate = DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager';

  return `
    <div class="sw-page-title">ขออัตรากำลัง</div>
    <div class="sw-page-subtitle">
      ผจก.สาขาขออัตรากำลัง → AM อนุมัติ → HR อนุมัติขั้นสุดท้าย
    </div>
    <div class="card mt-4">
      <div class="flex items-center" style="justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:14px">
        <div style="display:flex;gap:10px;flex-wrap:wrap">
          <span class="badge badge-warning" style="font-size:13px;padding:6px 12px">⏳ รออนุมัติ ${totalPending}</span>
          <span class="badge" style="font-size:13px;padding:6px 12px">รวมทั้งหมด ${list.length}</span>
        </div>
        ${canCreate ? `<button class="btn btn-primary" onclick="openHeadcountForm()">+ สร้างคำขอใหม่</button>` : ''}
      </div>
      <div class="sw-filter-bar" style="margin-bottom:14px">
        <select class="sw-filter-select" onchange="setHcFilter('year', this.value)" aria-label="กรองตามปี">
          <option value="">— ทุกปี —</option>
          ${_hcYears.map(y => `<option value="${y}" ${_hcFilter.year === y ? 'selected' : ''}>ปี ${Number(y) + 543}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setHcFilter('status', this.value)" aria-label="กรองตามสถานะ">
          <option value="">— ทุกสถานะ —</option>
          ${Object.entries(HC_STATUS_BADGE).map(([k, v]) => `<option value="${k}" ${_hcFilter.status === k ? 'selected' : ''}>${escapeHtml(v.label)}</option>`).join('')}
        </select>
        ${_hcHasFilter ? `<button class="btn btn-ghost btn-sm sw-filter-clear" onclick="clearHcFilter()">✕ ล้างตัวกรอง</button>` : ''}
      </div>
      ${list.length === 0 ? `
        <div class="empty-state" style="padding:32px">
          <div class="icon">📋</div>
          <div>${_hcHasFilter ? 'ไม่พบคำขอตามตัวกรอง' : 'ยังไม่มีคำขออัตรากำลัง'}</div>
          <div class="muted-2" style="font-size:13px;margin-top:6px">${_hcHasFilter ? 'ลองเปลี่ยน/ล้างตัวกรอง' : 'กด "+ สร้างคำขอใหม่" เพื่อขอเปิดอัตราพนักงาน'}</div>
        </div>
      ` : `
        <div class="table-wrap">
          <table class="table" style="font-size:13px">
            <thead><tr>
              <th>สถานะ</th>
              <th>วันที่ขอ</th>
              <th>สาขา</th>
              <th>ตำแหน่ง</th>
              <th>จำนวน</th>
              <th>เหตุผล</th>
              <th>หมายเหตุ</th>
              <th>การกระทำ</th>
            </tr></thead>
            <tbody>
              ${list.map(r => {
                const note = r.status === 'rejected' ? r.rejectReason : (r.status === 'cancelled' ? r.cancelReason : (r.hrNote || r.amNote || ''));
                const canReview = canActOn(r);
                const canCancel = ['pending_am','pending_hr'].includes(r.status) && (DB.isHR || r.requestedBy === DB.user?.id);
                const canFulfill = r.status === 'approved' && DB.isHR;
                return `<tr>
                  <td>${_hcBadgeHtml(r)}</td>
                  <td style="white-space:nowrap;font-size:12px">${fmt.date(r.requestedAt)}</td>
                  <td><code>${escapeHtml(r.branchId)}</code></td>
                  <td>${escapeHtml(r.positionTitle)}</td>
                  <td style="text-align:center"><strong>${fmt.num(r.headcount)}</strong></td>
                  <td style="max-width:240px;word-break:break-word">${escapeHtml(r.reason || '-')}</td>
                  <td style="max-width:200px;word-break:break-word;font-size:12px">${escapeHtml(note || '-')}</td>
                  <td>
                    ${canReview ? `
                      <button class="btn btn-success btn-sm" onclick="reviewHeadcountUI('${escapeHtml(r.id)}', 'approve')">✓ อนุมัติ</button>
                      <button class="btn btn-danger btn-sm" onclick="reviewHeadcountUI('${escapeHtml(r.id)}', 'reject')">✕ ปฏิเสธ</button>
                    ` : ''}
                    ${canFulfill ? `<button class="btn btn-success btn-sm" onclick="fulfillHeadcountUI('${escapeHtml(r.id)}')">🎯 เติมอัตราแล้ว</button>` : ''}
                    ${canCancel ? `<button class="btn btn-ghost btn-sm" onclick="cancelHeadcountUI('${escapeHtml(r.id)}')">ยกเลิก</button>` : ''}
                  </td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      `}
    </div>
  `;
});

function openHeadcountForm() {
  const role = DB.role;
  if (!(DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager')) {
    toast('ต้องเป็น ผจก.สาขา / AM / HR', 'error');
    return;
  }
  const myBranch = DB.getEmployee(DB.profile?.employee_id)?.branch || '';
  const branches = DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : [];
  // ตำแหน่งของสาขา — ตัดสายงานสำนักงาน (scope='office') ออก เหลือปฏิบัติการ + ที่ยังไม่ระบุสาย
  const positions = (DB.getPositions ? DB.getPositions() : []).filter(p => p.scope === 'operation');
  const lockBranch = (role === 'branch_manager' && myBranch);

  modal.open('สร้างคำขออัตรากำลัง', `
    <form id="hcReqForm" class="form-grid">
      <div class="form-group span-2">
        <label>สาขา *</label>
        ${lockBranch ? `
          <input value="${escapeHtml(myBranch)}" readonly/>
          <input type="hidden" name="branchId" value="${escapeHtml(myBranch)}"/>
        ` : `
          <select name="branchId" required>
            <option value="">— เลือกสาขา —</option>
            ${branches.map(b => `<option value="${escapeHtml(b.id)}" ${b.id === myBranch ? 'selected' : ''}>${escapeHtml(b.id)}</option>`).join('')}
          </select>
        `}
      </div>
      <div class="form-group span-2">
        <label>ตำแหน่งที่ขอ *</label>
        ${positions.length ? `
          <select name="positionId" required>
            <option value="">— เลือกตำแหน่ง —</option>
            ${positions.map(p => `<option value="${escapeHtml(p.id)}">${escapeHtml(p.name || p.id)}</option>`).join('')}
          </select>
        ` : `
          <input name="positionTitle" required placeholder="เช่น พนักงานขาย"/>
        `}
      </div>
      <div class="form-group">
        <label>จำนวน (อัตรา) *</label>
        <input type="number" name="headcount" required min="1" value="1"/>
      </div>
      <div class="form-group span-2">
        <label>เหตุผล</label>
        <textarea name="reason" rows="3" placeholder="เช่น ทดแทนพนักงานลาออก 2 คน / ขยายงานช่วงเทศกาล"></textarea>
      </div>
    </form>
  `, {
    size: 'sm',
    footer: '<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="hcReqSubmit">ส่งคำขอ</button>'
  });

  $('#hcReqSubmit').addEventListener('click', async () => {
    const form = $('#hcReqForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const fd = new FormData(form);
    const branchId = (fd.get('branchId') || '').toString().trim();
    const positionId = (fd.get('positionId') || '').toString().trim();
    let positionTitle = (fd.get('positionTitle') || '').toString().trim();
    if (!positionTitle && positionId) {
      const pos = (DB.getPositions ? DB.getPositions() : []).find(p => p.id === positionId);
      positionTitle = pos?.name || positionId;
    }
    const headcount = Number(fd.get('headcount') || 0);
    const reason = (fd.get('reason') || '').toString().trim();
    const btn = $('#hcReqSubmit'); btn.disabled = true; btn.textContent = 'กำลังส่ง...';
    try {
      await DB.createHeadcountRequest({ branchId, positionId, positionTitle, headcount, reason });
      modal.close();
      toast('✓ ส่งคำขอแล้ว — รอ AM อนุมัติ', 'success');
      router.go('headcount');
    } catch (ex) {
      toast(ex.message || String(ex), 'error');
      btn.disabled = false; btn.textContent = 'ส่งคำขอ';
    }
  });
}

async function reviewHeadcountUI(requestId, decision) {
  const action = decision === 'approve' ? 'อนุมัติ' : 'ปฏิเสธ';
  const note = await modal.prompt(`${action}คำขออัตรากำลัง`, 'กรอกหมายเหตุ (ทางเลือก):', '');
  if (note === null) return;
  try {
    await DB.reviewHeadcountRequest(requestId, decision, note);
    toast(`✓ ${action}คำขอแล้ว`, 'success');
    router.go('headcount');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

async function cancelHeadcountUI(requestId) {
  const reason = await modal.prompt('ยกเลิกคำขออัตรากำลัง', 'เหตุผลที่ยกเลิก (ทางเลือก):', '');
  if (reason === null) return;
  try {
    await DB.cancelHeadcountRequest(requestId, reason);
    toast('ยกเลิกคำขอแล้ว', 'success');
    router.go('headcount');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

async function fulfillHeadcountUI(requestId) {
  const note = await modal.prompt('ยืนยันเติมอัตราแล้ว', 'หมายเหตุ เช่น ชื่อพนักงานที่รับเข้า (ทางเลือก):', '');
  if (note === null) return;
  try {
    await DB.fulfillHeadcountRequest(requestId, note);
    toast('🎯 ปิดคำขอ — เติมอัตราเรียบร้อย', 'success');
    router.go('headcount');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

function updateHeadcountBadge() {
  const badge = document.getElementById('navBadgeHeadcount');
  if (!badge) return;
  const list = DB.data.headcountRequests || [];
  let pending = 0;
  if (DB.isHR) {
    pending = list.filter(r => r.status === 'pending_hr').length;
  } else if (DB.role === 'area_manager' || DB.role === 'operation_manager') {
    const managed = DB._managedBranches || [];
    pending = list.filter(r => r.status === 'pending_am' && managed.includes(r.branchId)).length;
  }
  if (pending > 0) {
    badge.textContent = String(pending);
    badge.style.display = 'inline-block';
    badge.title = `${pending} คำขออัตรากำลังรออนุมัติ`;
  } else {
    badge.style.display = 'none';
  }
}

// ═══════════════════════════════════════════════════════════
// RESIGNATION REPORTS — หน้า "แจ้งพนักงานลาออก" (BM → AM/OM/HR ทราบ)
// ═══════════════════════════════════════════════════════════
const RSG_STATUS_BADGE = {
  reported:     { label: '🔔 แจ้งลาออก — รอรับทราบ', cls: 'badge-warning' },
  acknowledged: { label: '✓ รับทราบแล้ว',            cls: 'badge-success' },
  cancelled:    { label: '⊘ ยกเลิก',                  cls: 'badge-neutral' }
};
function _rsgBadgeHtml(r) {
  const base = RSG_STATUS_BADGE[r.status] || { label: r.status, cls: 'badge' };
  return `<span class="badge ${base.cls}">${escapeHtml(base.label)}</span>`;
}

const _rsgFilter = { year: '', month: '', status: '' };
function setRsgFilter(k, v) { _rsgFilter[k] = v || ''; router.go('resignations'); }
function clearRsgFilter() { _rsgFilter.year = ''; _rsgFilter.month = ''; _rsgFilter.status = ''; router.go('resignations'); }

router.register('resignations', () => {
  const allList = DB.getResignationReports();
  const role = DB.role;
  // ─── ตัวกรอง: ปี (จากวันที่แจ้ง) + สถานะ ───
  const list = allList.filter(r => {
    if (_rsgFilter.year && String(r.reportedAt || '').slice(0, 4) !== _rsgFilter.year) return false;
    if (_rsgFilter.month && String(r.reportedAt || '').slice(5, 7) !== _rsgFilter.month) return false;
    if (_rsgFilter.status && r.status !== _rsgFilter.status) return false;
    return true;
  });
  const _rsgHasFilter = !!(_rsgFilter.year || _rsgFilter.month || _rsgFilter.status);
  const _rsgYears = (() => {
    const ty = new Date().getFullYear();
    const ys = new Set(allList.map(r => String(r.reportedAt || '').slice(0, 4)).filter(Boolean));
    for (let y = ty - 5; y <= ty; y++) ys.add(String(y));
    return Array.from(ys).filter(Boolean).sort((a, b) => Number(b) - Number(a));
  })();
  const totalReported = allList.filter(r => r.status === 'reported').length;
  const canCreate = DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager';

  return `
    <div class="sw-page-title">แจ้งพนักงานลาออก</div>
    <div class="sw-page-subtitle">
      ผจก.สาขาแจ้งพนักงานที่ขอลาออก → AM/OM และ HR ทราบ · HR กด "รับทราบ" เพื่อปิดเรื่อง (การตั้งวันพ้นสภาพจริงทำในเมนูทะเบียนพนักงาน)
    </div>
    <div class="card mt-4">
      <div class="flex items-center" style="justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:14px">
        <div style="display:flex;gap:10px;flex-wrap:wrap">
          <span class="badge badge-warning" style="font-size:13px;padding:6px 12px">🔔 รอรับทราบ ${totalReported}</span>
          <span class="badge" style="font-size:13px;padding:6px 12px">รวมทั้งหมด ${list.length}</span>
        </div>
        ${canCreate ? `<button class="btn btn-primary" onclick="openResignationForm()">+ แจ้งพนักงานลาออก</button>` : ''}
      </div>
      <div class="sw-filter-bar" style="margin-bottom:14px">
        <select class="sw-filter-select" onchange="setRsgFilter('year', this.value)" aria-label="กรองตามปี">
          <option value="">— ทุกปี —</option>
          ${_rsgYears.map(y => `<option value="${y}" ${_rsgFilter.year === y ? 'selected' : ''}>ปี ${Number(y) + 543}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setRsgFilter('month', this.value)" aria-label="กรองตามเดือน">
          <option value="">— ทุกเดือน —</option>
          ${['01','02','03','04','05','06','07','08','09','10','11','12'].map((m, i) => `<option value="${m}" ${_rsgFilter.month === m ? 'selected' : ''}>${['ม.ค.','ก.พ.','มี.ค.','เม.ย.','พ.ค.','มิ.ย.','ก.ค.','ส.ค.','ก.ย.','ต.ค.','พ.ย.','ธ.ค.'][i]}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setRsgFilter('status', this.value)" aria-label="กรองตามสถานะ">
          <option value="">— ทุกสถานะ —</option>
          ${Object.entries(RSG_STATUS_BADGE).map(([k, v]) => `<option value="${k}" ${_rsgFilter.status === k ? 'selected' : ''}>${escapeHtml(v.label)}</option>`).join('')}
        </select>
        ${_rsgHasFilter ? `<button class="btn btn-ghost btn-sm sw-filter-clear" onclick="clearRsgFilter()">✕ ล้างตัวกรอง</button>` : ''}
      </div>
      ${list.length === 0 ? `
        <div class="empty-state" style="padding:32px">
          <div class="icon">📋</div>
          <div>${_rsgHasFilter ? 'ไม่พบรายการตามตัวกรอง' : 'ยังไม่มีการแจ้งพนักงานลาออก'}</div>
          <div class="muted-2" style="font-size:13px;margin-top:6px">${_rsgHasFilter ? 'ลองเปลี่ยน/ล้างตัวกรอง' : (canCreate ? 'กด "+ แจ้งพนักงานลาออก" เพื่อแจ้งให้ AM/OM/HR ทราบ' : 'ยังไม่มีรายการ')}</div>
        </div>
      ` : `
        <div class="table-wrap">
          <table class="table" style="font-size:13px">
            <thead><tr>
              <th>สถานะ</th>
              <th>วันที่แจ้ง</th>
              <th>สาขา</th>
              <th>พนักงาน</th>
              <th>ตำแหน่ง</th>
              <th>วันมีผล</th>
              <th>เหตุผล / หมายเหตุ</th>
              <th>การกระทำ</th>
            </tr></thead>
            <tbody>
              ${list.map(r => {
                const canAck = r.status === 'reported' && DB.isHR;
                const canCancel = r.status === 'reported' && (DB.isHR || r.reportedBy === DB.user?.id);
                const e = DB.getEmployee(r.employeeId);
                const empName = r.employeeName || (e ? `${e.firstName || ''} ${e.lastName || ''}`.trim() : r.employeeId);
                return `<tr>
                  <td>${_rsgBadgeHtml(r)}</td>
                  <td style="white-space:nowrap;font-size:12px">${fmt.date(r.reportedAt)}</td>
                  <td><code>${escapeHtml(r.branchId)}</code></td>
                  <td><a href="#" onclick="viewEmployee('${escapeHtml(r.employeeId)}');return false;">${escapeHtml(empName || '-')}</a></td>
                  <td>${escapeHtml(r.positionTitle || '-')}</td>
                  <td style="white-space:nowrap;font-size:12px">${r.resignDate ? fmt.date(r.resignDate) : '-'}</td>
                  <td style="max-width:260px;word-break:break-word">${escapeHtml(r.reason || '-')}${r.note ? `<br><span class="muted-2" style="font-size:11px">${escapeHtml(r.note)}</span>` : ''}</td>
                  <td>
                    ${canAck ? `<button class="btn btn-success btn-sm" onclick="acknowledgeResignationUI('${escapeHtml(r.id)}')">✓ รับทราบ</button>` : ''}
                    ${canCancel ? `<button class="btn btn-ghost btn-sm" onclick="cancelResignationUI('${escapeHtml(r.id)}')">ยกเลิก</button>` : ''}
                    ${r.status === 'acknowledged' && r.acknowledgeNote ? `<span class="muted-2" style="font-size:11px">📝 ${escapeHtml(r.acknowledgeNote)}</span>` : ''}
                    ${r.status === 'cancelled' && r.cancelReason ? `<span class="muted-2" style="font-size:11px">${escapeHtml(r.cancelReason)}</span>` : ''}
                  </td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      `}
    </div>
  `;
});

function openResignationForm() {
  const role = DB.role;
  if (!(DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager')) {
    toast('ต้องเป็น ผจก.สาขา / AM / OM / HR', 'error');
    return;
  }
  const myBranch = DB.getEmployee(DB.profile?.employee_id)?.branch || '';
  const branches = DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : [];
  const lockBranch = (role === 'branch_manager' && myBranch);
  const initialBranch = lockBranch ? myBranch : (myBranch || '');

  // สร้าง <option> รายชื่อพนักงาน (active) ของสาขาที่เลือก — auto-scope ตามสิทธิ์ user อยู่แล้ว
  const empOptions = (branchId) => {
    if (!branchId) return '<option value="">— เลือกสาขาก่อน —</option>';
    const emps = DB.getEmployees({ branch: branchId, status: 'active' })
      .slice().sort((a, b) => String(a.id).localeCompare(String(b.id)));
    if (!emps.length) return '<option value="">— ไม่มีพนักงานในสาขานี้ —</option>';
    return '<option value="">— เลือกพนักงาน —</option>' + emps.map(e =>
      `<option value="${escapeHtml(e.id)}">${escapeHtml(e.id)} · ${escapeHtml(`${e.firstName || ''} ${e.lastName || ''}`.trim())}${e.nickname ? ' (' + escapeHtml(e.nickname) + ')' : ''}${e.positionTitle ? ' — ' + escapeHtml(e.positionTitle) : ''}</option>`
    ).join('');
  };

  modal.open('แจ้งพนักงานลาออก', `
    <form id="rsgReqForm" class="form-grid">
      <div class="form-group span-2">
        <label>สาขา *</label>
        ${lockBranch ? `
          <input value="${escapeHtml(myBranch)}" readonly/>
          <input type="hidden" name="branchId" value="${escapeHtml(myBranch)}"/>
        ` : `
          <select name="branchId" id="rsgBranchSel" required>
            <option value="">— เลือกสาขา —</option>
            ${branches.map(b => `<option value="${escapeHtml(b.id)}" ${b.id === myBranch ? 'selected' : ''}>${escapeHtml(b.id)}</option>`).join('')}
          </select>
        `}
      </div>
      <div class="form-group span-2">
        <label>พนักงานที่ขอลาออก *</label>
        <select name="employeeId" id="rsgEmpSel" required>${empOptions(initialBranch)}</select>
      </div>
      <div class="form-group">
        <label>วันที่มีผล (วันทำงานวันสุดท้าย)</label>
        <input type="date" name="resignDate"/>
      </div>
      <div class="form-group span-2">
        <label>เหตุผลการลาออก</label>
        <textarea name="reason" rows="2" placeholder="เช่น ย้ายกลับภูมิลำเนา / ได้งานใหม่ / ปัญหาส่วนตัว"></textarea>
      </div>
      <div class="form-group span-2">
        <label>หมายเหตุเพิ่มเติม</label>
        <textarea name="note" rows="2" placeholder="รายละเอียดอื่นๆ ที่อยากให้ AM/OM/HR ทราบ"></textarea>
      </div>
    </form>
  `, {
    size: 'sm',
    footer: '<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="rsgReqSubmit">ส่งแจ้ง</button>'
  });

  // เปลี่ยนสาขา → โหลดรายชื่อพนักงานใหม่ (เฉพาะกรณีเลือกสาขาได้ — AM/OM/HR)
  const branchSel = document.getElementById('rsgBranchSel');
  if (branchSel) {
    branchSel.addEventListener('change', () => {
      const empSel = document.getElementById('rsgEmpSel');
      if (empSel) empSel.innerHTML = empOptions(branchSel.value);
    });
  }

  $('#rsgReqSubmit').addEventListener('click', async () => {
    const form = $('#rsgReqForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const fd = new FormData(form);
    const branchId = (fd.get('branchId') || '').toString().trim();
    const employeeId = (fd.get('employeeId') || '').toString().trim();
    const resignDate = (fd.get('resignDate') || '').toString().trim();
    const reason = (fd.get('reason') || '').toString().trim();
    const note = (fd.get('note') || '').toString().trim();
    const emp = DB.getEmployee(employeeId) || {};
    const employeeName = `${emp.firstName || ''} ${emp.lastName || ''}`.trim();
    const positionTitle = emp.positionTitle || '';
    const btn = $('#rsgReqSubmit'); btn.disabled = true; btn.textContent = 'กำลังส่ง...';
    try {
      await DB.createResignationReport({ branchId, employeeId, employeeName, positionTitle, resignDate, reason, note });
      modal.close();
      toast('✓ แจ้งลาออกแล้ว — AM/OM/HR จะเห็นทันที', 'success');
      router.go('resignations');
    } catch (ex) {
      toast(ex.message || String(ex), 'error');
      btn.disabled = false; btn.textContent = 'ส่งแจ้ง';
    }
  });
}

