// ═══════════════════════════════════════════════════════════
// OVERTIME REQUESTS — หน้า "ขอทำงานล่วงเวลา (OT)" (BM ขอ → AM/HR อนุมัติ)
// ═══════════════════════════════════════════════════════════
const OT_STATUS_BADGE = {
  pending:   { label: '⏳ รออนุมัติ',   cls: 'badge-warning' },
  approved:  { label: '✓ อนุมัติแล้ว',  cls: 'badge-success' },
  rejected:  { label: '✕ ไม่อนุมัติ',   cls: 'badge-danger' },
  cancelled: { label: '⊘ ยกเลิก',       cls: 'badge-neutral' }
};
function _otBadgeHtml(r) {
  const base = OT_STATUS_BADGE[r.status] || { label: r.status, cls: 'badge' };
  let html = `<span class="badge ${base.cls}">${escapeHtml(base.label)}</span>`;
  if (r.status === 'rejected' && r.approverNote) {
    html += `<br><span class="muted-2" style="font-size:10.5px">${escapeHtml(r.approverNote)}</span>`;
  }
  return html;
}

// คำนวณชั่วโมงจาก HH:MM (ข้ามเที่ยงคืน +24) — ตรงกับสูตรใน RPC
function _otCalcHours(start, end) {
  if (!start || !end) return 0;
  const [h1, m1] = start.split(':').map(Number);
  const [h2, m2] = end.split(':').map(Number);
  if ([h1, m1, h2, m2].some(n => Number.isNaN(n))) return 0;
  let mins = (h2 * 60 + m2) - (h1 * 60 + m1);
  if (mins <= 0) mins += 24 * 60;
  return +(mins / 60).toFixed(2);
}

const _otFilter = { year: '', month: '', status: '' };
function setOtFilter(k, v) { _otFilter[k] = v || ''; router.go('overtime'); }
function clearOtFilter() { _otFilter.year = ''; _otFilter.month = ''; _otFilter.status = ''; router.go('overtime'); }

router.register('overtime', () => {
  const allList = DB.getOvertimeRequests();
  const role = DB.role;
  const list = allList.filter(r => {
    if (_otFilter.year && String(r.otDate || '').slice(0, 4) !== _otFilter.year) return false;
    if (_otFilter.month && String(r.otDate || '').slice(5, 7) !== _otFilter.month) return false;
    if (_otFilter.status && r.status !== _otFilter.status) return false;
    return true;
  });
  const _otHasFilter = !!(_otFilter.year || _otFilter.month || _otFilter.status);
  const _otYears = (() => {
    const ty = new Date().getFullYear();
    const ys = new Set(allList.map(r => String(r.otDate || '').slice(0, 4)).filter(Boolean));
    for (let y = ty - 5; y <= ty + 1; y++) ys.add(String(y));
    return Array.from(ys).filter(Boolean).sort((a, b) => Number(b) - Number(a));
  })();
  const managed = DB._managedBranches || [];
  const canActOn = (r) => r.status === 'pending' && (DB.isHR || ((role === 'area_manager' || role === 'operation_manager') && managed.includes(r.branchId)));
  const totalPending = allList.filter(r => r.status === 'pending').length;
  const canCreate = DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager';

  return `
    <div class="sw-page-title">ขอทำงานล่วงเวลา (OT)</div>
    <div class="sw-page-subtitle">
      ผจก.สาขาขอ OT ให้พนักงานประจำสายงาน operation → AM หรือ HR อนุมัติ · ระบบคำนวณชั่วโมงให้อัตโนมัติ
    </div>
    <div class="card mt-4">
      <div class="flex items-center" style="justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:14px">
        <div style="display:flex;gap:10px;flex-wrap:wrap">
          <span class="badge badge-warning" style="font-size:13px;padding:6px 12px">⏳ รออนุมัติ ${totalPending}</span>
          <span class="badge" style="font-size:13px;padding:6px 12px">รวมทั้งหมด ${list.length}</span>
        </div>
        ${canCreate ? `<button class="btn btn-primary" onclick="openOvertimeForm()">+ ขอ OT</button>` : ''}
      </div>
      <div class="sw-filter-bar" style="margin-bottom:14px">
        <select class="sw-filter-select" onchange="setOtFilter('year', this.value)" aria-label="กรองตามปี">
          <option value="">— ทุกปี —</option>
          ${_otYears.map(y => `<option value="${y}" ${_otFilter.year === y ? 'selected' : ''}>ปี ${Number(y) + 543}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setOtFilter('month', this.value)" aria-label="กรองตามเดือน">
          <option value="">— ทุกเดือน —</option>
          ${['01','02','03','04','05','06','07','08','09','10','11','12'].map((m, i) => `<option value="${m}" ${_otFilter.month === m ? 'selected' : ''}>${['ม.ค.','ก.พ.','มี.ค.','เม.ย.','พ.ค.','มิ.ย.','ก.ค.','ส.ค.','ก.ย.','ต.ค.','พ.ย.','ธ.ค.'][i]}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setOtFilter('status', this.value)" aria-label="กรองตามสถานะ">
          <option value="">— ทุกสถานะ —</option>
          ${Object.entries(OT_STATUS_BADGE).map(([k, v]) => `<option value="${k}" ${_otFilter.status === k ? 'selected' : ''}>${escapeHtml(v.label)}</option>`).join('')}
        </select>
        ${_otHasFilter ? `<button class="btn btn-ghost btn-sm sw-filter-clear" onclick="clearOtFilter()">✕ ล้างตัวกรอง</button>` : ''}
      </div>
      ${list.length === 0 ? `
        <div class="empty-state" style="padding:32px">
          <div class="icon">⏱️</div>
          <div>${_otHasFilter ? 'ไม่พบคำขอตามตัวกรอง' : 'ยังไม่มีคำขอ OT'}</div>
          <div class="muted-2" style="font-size:13px;margin-top:6px">${_otHasFilter ? 'ลองเปลี่ยน/ล้างตัวกรอง' : (canCreate ? 'กด "+ ขอ OT" เพื่อขอทำงานล่วงเวลาให้พนักงานประจำสาย operation' : 'ยังไม่มีรายการ')}</div>
        </div>
      ` : `
        <div class="table-wrap">
          <table class="table" style="font-size:13px">
            <thead><tr>
              <th>สถานะ</th>
              <th>วันที่ OT</th>
              <th>พนักงาน</th>
              <th>สาขา</th>
              <th>เวลา</th>
              <th>ชม.</th>
              <th>เหตุผล</th>
              <th>การกระทำ</th>
            </tr></thead>
            <tbody>
              ${list.map(r => {
                const canReview = canActOn(r);
                const canCancel = r.status === 'pending' && (DB.isHR || r.requestedBy === DB.user?.id);
                const e = DB.getEmployee(r.employeeId);
                const empName = r.employeeName || (e ? `${e.firstName || ''} ${e.lastName || ''}`.trim() : r.employeeId);
                const tt = `${(r.startTime || '').slice(0, 5)}–${(r.endTime || '').slice(0, 5)}`;
                return `<tr>
                  <td>${_otBadgeHtml(r)}</td>
                  <td style="white-space:nowrap;font-size:12px">${r.otDate ? fmt.date(r.otDate) : '-'}</td>
                  <td><a href="#" onclick="viewEmployee('${escapeHtml(r.employeeId)}');return false;">${escapeHtml(empName || '-')}</a></td>
                  <td><code>${escapeHtml(r.branchId)}</code></td>
                  <td style="white-space:nowrap;font-size:12px">${escapeHtml(tt)}</td>
                  <td style="text-align:center"><strong>${r.otHours != null ? r.otHours : '-'}</strong></td>
                  <td style="max-width:220px;word-break:break-word">${escapeHtml(r.reason || '-')}</td>
                  <td>
                    ${canReview ? `
                      <button class="btn btn-success btn-sm" onclick="reviewOvertimeUI('${escapeHtml(r.id)}', 'approve')">✓ อนุมัติ</button>
                      <button class="btn btn-danger btn-sm" onclick="reviewOvertimeUI('${escapeHtml(r.id)}', 'reject')">✕ ปฏิเสธ</button>
                    ` : ''}
                    ${canCancel ? `<button class="btn btn-ghost btn-sm" onclick="cancelOvertimeUI('${escapeHtml(r.id)}')">ยกเลิก</button>` : ''}
                  </td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      `}
    </div>
  `;
});

function openOvertimeForm() {
  const role = DB.role;
  if (!(DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager')) {
    toast('ต้องเป็น ผจก.สาขา / AM / OM / HR', 'error');
    return;
  }
  const myBranch = DB.getEmployee(DB.profile?.employee_id)?.branch || '';
  const branches = DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : [];
  const lockBranch = (role === 'branch_manager' && myBranch);
  const initialBranch = lockBranch ? myBranch : (myBranch || '');

  // เฉพาะพนักงานประจำ (full-time) สายงาน operation ที่ยัง active
  const empOptions = (branchId) => {
    if (!branchId) return '<option value="">— เลือกสาขาก่อน —</option>';
    const emps = DB.getEmployees({ branch: branchId, scope: 'operation', status: 'active' })
      .filter(e => e.employeeType === 'พนักงานประจำ')
      .slice().sort((a, b) => String(a.id).localeCompare(String(b.id)));
    if (!emps.length) return '<option value="">— ไม่มีพนักงานประจำสาย operation ในสาขานี้ —</option>';
    return '<option value="">— เลือกพนักงาน —</option>' + emps.map(e =>
      `<option value="${escapeHtml(e.id)}">${escapeHtml(e.id)} · ${escapeHtml(`${e.firstName || ''} ${e.lastName || ''}`.trim())}${e.positionTitle ? ' — ' + escapeHtml(e.positionTitle) : ''}</option>`
    ).join('');
  };

  modal.open('ขอทำงานล่วงเวลา (OT)', `
    <form id="otReqForm" class="form-grid">
      <div class="form-group span-2">
        <label>สาขา *</label>
        ${lockBranch ? `
          <input value="${escapeHtml(myBranch)}" readonly/>
          <input type="hidden" name="branchId" value="${escapeHtml(myBranch)}"/>
        ` : `
          <select name="branchId" id="otBranchSel" required>
            <option value="">— เลือกสาขา —</option>
            ${branches.map(b => `<option value="${escapeHtml(b.id)}" ${b.id === myBranch ? 'selected' : ''}>${escapeHtml(b.id)}</option>`).join('')}
          </select>
        `}
      </div>
      <div class="form-group span-2">
        <label>พนักงาน (เฉพาะพนักงานประจำ สาย operation) *</label>
        <select name="employeeId" id="otEmpSel" required>${empOptions(initialBranch)}</select>
      </div>
      <div class="form-group">
        <label>วันที่ทำ OT *</label>
        <input type="date" name="otDate" required/>
      </div>
      <div class="form-group">
        <label>รวมชั่วโมง</label>
        <input type="text" id="otHoursPreview" readonly value="—" style="font-weight:700;background:var(--surface-2)"/>
      </div>
      <div class="form-group">
        <label>เวลาเริ่ม *</label>
        <input type="time" name="startTime" id="otStart" required/>
      </div>
      <div class="form-group">
        <label>เวลาเลิก *</label>
        <input type="time" name="endTime" id="otEnd" required/>
      </div>
      <div class="form-group span-2">
        <label>เหตุผล / งานที่ทำ</label>
        <textarea name="reason" rows="2" placeholder="เช่น ปิดร้านช่วงเทศกาล / รับลูกค้ากรุ๊ปใหญ่ / ทำงานต่อกะดึก"></textarea>
      </div>
    </form>
  `, {
    size: 'sm',
    footer: '<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="otReqSubmit">ส่งคำขอ</button>'
  });

  const branchSel = document.getElementById('otBranchSel');
  if (branchSel) {
    branchSel.addEventListener('change', () => {
      const empSel = document.getElementById('otEmpSel');
      if (empSel) empSel.innerHTML = empOptions(branchSel.value);
    });
  }
  // live preview ชั่วโมง OT
  const updHrs = () => {
    const s = document.getElementById('otStart')?.value || '';
    const en = document.getElementById('otEnd')?.value || '';
    const h = _otCalcHours(s, en);
    const prev = document.getElementById('otHoursPreview');
    if (prev) prev.value = (s && en && h > 0) ? `${h} ชม.` : '—';
  };
  document.getElementById('otStart')?.addEventListener('input', updHrs);
  document.getElementById('otEnd')?.addEventListener('input', updHrs);

  $('#otReqSubmit').addEventListener('click', async () => {
    const form = $('#otReqForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const fd = new FormData(form);
    const branchId = (fd.get('branchId') || '').toString().trim();
    const employeeId = (fd.get('employeeId') || '').toString().trim();
    const otDate = (fd.get('otDate') || '').toString().trim();
    const startTime = (fd.get('startTime') || '').toString().trim();
    const endTime = (fd.get('endTime') || '').toString().trim();
    const reason = (fd.get('reason') || '').toString().trim();
    if (_otCalcHours(startTime, endTime) <= 0) { toast('เวลาเริ่ม-เลิกไม่ถูกต้อง', 'warning'); return; }
    const emp = DB.getEmployee(employeeId) || {};
    const employeeName = `${emp.firstName || ''} ${emp.lastName || ''}`.trim();
    const positionTitle = emp.positionTitle || '';
    const btn = $('#otReqSubmit'); btn.disabled = true; btn.textContent = 'กำลังส่ง...';
    try {
      await DB.createOvertimeRequest({ branchId, employeeId, employeeName, positionTitle, otDate, startTime, endTime, reason });
      modal.close();
      toast('✓ ส่งคำขอ OT แล้ว — รอ AM/HR อนุมัติ', 'success');
      router.go('overtime');
    } catch (ex) {
      toast(ex.message || String(ex), 'error');
      btn.disabled = false; btn.textContent = 'ส่งคำขอ';
    }
  });
}

async function reviewOvertimeUI(requestId, decision) {
  const action = decision === 'approve' ? 'อนุมัติ' : 'ปฏิเสธ';
  const note = await modal.prompt(`${action}คำขอ OT`, 'หมายเหตุ (ทางเลือก):', '');
  if (note === null) return;
  try {
    await DB.reviewOvertimeRequest(requestId, decision, note);
    toast(`✓ ${action}คำขอแล้ว`, 'success');
    router.go('overtime');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

async function cancelOvertimeUI(requestId) {
  const reason = await modal.prompt('ยกเลิกคำขอ OT', 'เหตุผลที่ยกเลิก (ทางเลือก):', '');
  if (reason === null) return;
  try {
    await DB.cancelOvertimeRequest(requestId, reason);
    toast('ยกเลิกคำขอแล้ว', 'success');
    router.go('overtime');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

function updateOvertimeBadge() {
  const badge = document.getElementById('navBadgeOvertime');
  if (!badge) return;
  // นับเฉพาะคำขอที่ "ฉันอนุมัติได้" — AM/OM ในสาขาที่ดูแล หรือ HR เห็นทั้งหมด (BM ผู้ขอไม่นับ)
  const list = DB.data.overtimeRequests || [];
  let pending = 0;
  if (DB.isHR) {
    pending = list.filter(r => r.status === 'pending').length;
  } else if (DB.role === 'area_manager' || DB.role === 'operation_manager') {
    const managed = DB._managedBranches || [];
    pending = list.filter(r => r.status === 'pending' && managed.includes(r.branchId)).length;
  }
  if (pending > 0) {
    badge.textContent = String(pending);
    badge.style.display = 'inline-block';
    badge.title = `${pending} คำขอ OT รออนุมัติ`;
  } else {
    badge.style.display = 'none';
  }
}

// ═══════════════════════════════════════════════════════════
// SHIFT-CHANGE REQUESTS — หน้า "ขอเปลี่ยนกะย้อนหลัง" (BM ขอ → AM/HR อนุมัติ → แก้ตารางอัตโนมัติ)
// ═══════════════════════════════════════════════════════════
const SCR_STATUS_BADGE = {
  pending:   { label: '⏳ รออนุมัติ',      cls: 'badge-warning' },
  approved:  { label: '✓ อนุมัติ+แก้แล้ว', cls: 'badge-success' },
  rejected:  { label: '✕ ไม่อนุมัติ',      cls: 'badge-danger' },
  cancelled: { label: '⊘ ยกเลิก',          cls: 'badge-neutral' }
};
function _scrBadgeHtml(r) {
  const base = SCR_STATUS_BADGE[r.status] || { label: r.status, cls: 'badge' };
  let html = `<span class="badge ${base.cls}">${escapeHtml(base.label)}</span>`;
  if (r.status === 'rejected' && r.approverNote) {
    html += `<br><span class="muted-2" style="font-size:10.5px">${escapeHtml(r.approverNote)}</span>`;
  }
  return html;
}

const _scrFilter = { year: '', month: '', status: '' };
function setScrFilter(k, v) { _scrFilter[k] = v || ''; router.go('shift-changes'); }
function clearScrFilter() { _scrFilter.year = ''; _scrFilter.month = ''; _scrFilter.status = ''; router.go('shift-changes'); }

router.register('shift-changes', () => {
  const allList = DB.getShiftChangeRequests();
  const role = DB.role;
  const list = allList.filter(r => {
    if (_scrFilter.year && String(r.workDate || '').slice(0, 4) !== _scrFilter.year) return false;
    if (_scrFilter.month && String(r.workDate || '').slice(5, 7) !== _scrFilter.month) return false;
    if (_scrFilter.status && r.status !== _scrFilter.status) return false;
    return true;
  });
  const _scrHasFilter = !!(_scrFilter.year || _scrFilter.month || _scrFilter.status);
  const _scrYears = (() => {
    const ty = new Date().getFullYear();
    const ys = new Set(allList.map(r => String(r.workDate || '').slice(0, 4)).filter(Boolean));
    for (let y = ty - 5; y <= ty; y++) ys.add(String(y));
    return Array.from(ys).filter(Boolean).sort((a, b) => Number(b) - Number(a));
  })();
  const managed = DB._managedBranches || [];
  const canActOn = (r) => r.status === 'pending' && (DB.isHR || ((role === 'area_manager' || role === 'operation_manager') && managed.includes(r.branchId)));
  const totalPending = allList.filter(r => r.status === 'pending').length;
  const canCreate = DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager';

  return `
    <div class="sw-page-title">ขอเปลี่ยนกะย้อนหลัง</div>
    <div class="sw-page-subtitle">
      ผจก.สาขาขอแก้กะของวันที่ผ่านมาแล้ว → AM หรือ HR อนุมัติ · พออนุมัติ ระบบเปลี่ยนกะในตารางงานให้อัตโนมัติ
    </div>
    <div class="card mt-4">
      <div class="flex items-center" style="justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:14px">
        <div style="display:flex;gap:10px;flex-wrap:wrap">
          <span class="badge badge-warning" style="font-size:13px;padding:6px 12px">⏳ รออนุมัติ ${totalPending}</span>
          <span class="badge" style="font-size:13px;padding:6px 12px">รวมทั้งหมด ${list.length}</span>
        </div>
        ${canCreate ? `<button class="btn btn-primary" onclick="openShiftChangeForm()">+ ขอเปลี่ยนกะ</button>` : ''}
      </div>
      <div class="sw-filter-bar" style="margin-bottom:14px">
        <select class="sw-filter-select" onchange="setScrFilter('year', this.value)" aria-label="กรองตามปี">
          <option value="">— ทุกปี —</option>
          ${_scrYears.map(y => `<option value="${y}" ${_scrFilter.year === y ? 'selected' : ''}>ปี ${Number(y) + 543}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setScrFilter('month', this.value)" aria-label="กรองตามเดือน">
          <option value="">— ทุกเดือน —</option>
          ${['01','02','03','04','05','06','07','08','09','10','11','12'].map((m, i) => `<option value="${m}" ${_scrFilter.month === m ? 'selected' : ''}>${['ม.ค.','ก.พ.','มี.ค.','เม.ย.','พ.ค.','มิ.ย.','ก.ค.','ส.ค.','ก.ย.','ต.ค.','พ.ย.','ธ.ค.'][i]}</option>`).join('')}
        </select>
        <select class="sw-filter-select" onchange="setScrFilter('status', this.value)" aria-label="กรองตามสถานะ">
          <option value="">— ทุกสถานะ —</option>
          ${Object.entries(SCR_STATUS_BADGE).map(([k, v]) => `<option value="${k}" ${_scrFilter.status === k ? 'selected' : ''}>${escapeHtml(v.label)}</option>`).join('')}
        </select>
        ${_scrHasFilter ? `<button class="btn btn-ghost btn-sm sw-filter-clear" onclick="clearScrFilter()">✕ ล้างตัวกรอง</button>` : ''}
      </div>
      ${list.length === 0 ? `
        <div class="empty-state" style="padding:32px">
          <div class="icon">🔄</div>
          <div>${_scrHasFilter ? 'ไม่พบคำขอตามตัวกรอง' : 'ยังไม่มีคำขอเปลี่ยนกะ'}</div>
          <div class="muted-2" style="font-size:13px;margin-top:6px">${_scrHasFilter ? 'ลองเปลี่ยน/ล้างตัวกรอง' : (canCreate ? 'กด "+ ขอเปลี่ยนกะ" เพื่อขอแก้กะของวันที่ผ่านมาแล้ว' : 'ยังไม่มีรายการ')}</div>
        </div>
      ` : `
        <div class="table-wrap">
          <table class="table" style="font-size:13px">
            <thead><tr>
              <th>สถานะ</th>
              <th>วันที่</th>
              <th>พนักงาน</th>
              <th>สาขา</th>
              <th>เปลี่ยนกะ</th>
              <th>เหตุผล</th>
              <th>การกระทำ</th>
            </tr></thead>
            <tbody>
              ${list.map(r => {
                const canReview = canActOn(r);
                const canCancel = r.status === 'pending' && (DB.isHR || r.requestedBy === DB.user?.id);
                const e = DB.getEmployee(r.employeeId);
                const empName = r.employeeName || (e ? `${e.firstName || ''} ${e.lastName || ''}`.trim() : r.employeeId);
                return `<tr>
                  <td>${_scrBadgeHtml(r)}</td>
                  <td style="white-space:nowrap;font-size:12px">${r.workDate ? fmt.date(r.workDate) : '-'}</td>
                  <td><a href="#" onclick="viewEmployee('${escapeHtml(r.employeeId)}');return false;">${escapeHtml(empName || '-')}</a></td>
                  <td><code>${escapeHtml(r.branchId)}</code></td>
                  <td style="white-space:nowrap"><span class="muted-2">${escapeHtml(r.oldShiftCode || '—')}</span> → <strong>${escapeHtml(r.newShiftCode || '-')}</strong></td>
                  <td style="max-width:220px;word-break:break-word">${escapeHtml(r.reason || '-')}</td>
                  <td>
                    ${canReview ? `
                      <button class="btn btn-success btn-sm" onclick="reviewShiftChangeUI('${escapeHtml(r.id)}', 'approve')">✓ อนุมัติ</button>
                      <button class="btn btn-danger btn-sm" onclick="reviewShiftChangeUI('${escapeHtml(r.id)}', 'reject')">✕ ปฏิเสธ</button>
                    ` : ''}
                    ${canCancel ? `<button class="btn btn-ghost btn-sm" onclick="cancelShiftChangeUI('${escapeHtml(r.id)}')">ยกเลิก</button>` : ''}
                  </td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      `}
    </div>
  `;
});

function openShiftChangeForm() {
  const role = DB.role;
  if (!(DB.isHR || role === 'branch_manager' || role === 'area_manager' || role === 'operation_manager')) {
    toast('ต้องเป็น ผจก.สาขา / AM / OM / HR', 'error');
    return;
  }
  const myBranch = DB.getEmployee(DB.profile?.employee_id)?.branch || '';
  const branches = DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : [];
  const lockBranch = (role === 'branch_manager' && myBranch);
  const initialBranch = lockBranch ? myBranch : (myBranch || '');
  // วันสูงสุด = เมื่อวาน (ย้อนหลังเท่านั้น) — คำนวณแบบ UTC กัน timezone เพี้ยน
  const _p = DB.todayBkk().split('-').map(Number);
  const _d = new Date(Date.UTC(_p[0], _p[1] - 1, _p[2])); _d.setUTCDate(_d.getUTCDate() - 1);
  const maxDate = _d.toISOString().slice(0, 10);

  const empOptions = (branchId) => {
    if (!branchId) return '<option value="">— เลือกสาขาก่อน —</option>';
    const emps = DB.getEmployees({ branch: branchId, status: 'active' })
      .slice().sort((a, b) => String(a.id).localeCompare(String(b.id)));
    if (!emps.length) return '<option value="">— ไม่มีพนักงานในสาขานี้ —</option>';
    return '<option value="">— เลือกพนักงาน —</option>' + emps.map(e =>
      `<option value="${escapeHtml(e.id)}">${escapeHtml(e.id)} · ${escapeHtml(`${e.firstName || ''} ${e.lastName || ''}`.trim())}${e.positionTitle ? ' — ' + escapeHtml(e.positionTitle) : ''}</option>`
    ).join('');
  };
  const shiftOptions = (branchId) => {
    const shifts = DB.getShifts ? DB.getShifts({ branchId, activeOnly: true }) : [];
    if (!shifts.length) return '<option value="">— ไม่มีกะ —</option>';
    return '<option value="">— เลือกกะใหม่ —</option>' + shifts.map(s =>
      `<option value="${escapeHtml(s.id)}">${escapeHtml(s.code)}${s.name ? ' · ' + escapeHtml(s.name) : ''}${(!s.isOffDay && s.startTime) ? ' (' + s.startTime.slice(0, 5) + '–' + (s.endTime || '').slice(0, 5) + ')' : ''}</option>`
    ).join('');
  };

  modal.open('ขอเปลี่ยนกะย้อนหลัง', `
    <form id="scrReqForm" class="form-grid">
      <div class="form-group span-2">
        <label>สาขา *</label>
        ${lockBranch ? `
          <input value="${escapeHtml(myBranch)}" readonly/>
          <input type="hidden" name="branchId" value="${escapeHtml(myBranch)}"/>
        ` : `
          <select name="branchId" id="scrBranchSel" required>
            <option value="">— เลือกสาขา —</option>
            ${branches.map(b => `<option value="${escapeHtml(b.id)}" ${b.id === myBranch ? 'selected' : ''}>${escapeHtml(b.id)}</option>`).join('')}
          </select>
        `}
      </div>
      <div class="form-group span-2">
        <label>พนักงาน *</label>
        <select name="employeeId" id="scrEmpSel" required>${empOptions(initialBranch)}</select>
      </div>
      <div class="form-group">
        <label>วันที่ (ย้อนหลัง) *</label>
        <input type="date" name="workDate" id="scrDate" max="${maxDate}" required/>
      </div>
      <div class="form-group">
        <label>กะเดิมวันนั้น</label>
        <input type="text" id="scrOldShift" readonly value="—" style="background:var(--surface-2)"/>
      </div>
      <div class="form-group span-2">
        <label>เปลี่ยนเป็นกะใหม่ *</label>
        <select name="newShiftId" id="scrNewShift" required>${shiftOptions(initialBranch)}</select>
      </div>
      <div class="form-group span-2">
        <label>เหตุผล</label>
        <textarea name="reason" rows="2" placeholder="เช่น ลงกะผิด / สลับกะกับเพื่อน / ลืมแก้ตอนนั้น"></textarea>
      </div>
    </form>
  `, {
    size: 'sm',
    footer: '<button class="btn btn-secondary" data-close>ยกเลิก</button><button class="btn btn-primary" id="scrReqSubmit">ส่งคำขอ</button>'
  });

  // lookup กะเดิมของพนักงาน+วันนั้น แสดงให้เห็นก่อนขอ
  const updOld = () => {
    const empId = document.getElementById('scrEmpSel')?.value || '';
    const wd = document.getElementById('scrDate')?.value || '';
    const out = document.getElementById('scrOldShift');
    if (!out) return;
    if (!empId || !wd) { out.value = '—'; return; }
    const ents = DB.getScheduleEntries ? DB.getScheduleEntries({ employeeId: empId, dateFrom: wd, dateTo: wd }) : [];
    const ent = ents[0];
    if (!ent) { out.value = '(ยังไม่มีกะในวันนั้น)'; return; }
    const sh = ent.shiftId ? DB.getShift(ent.shiftId) : null;
    out.value = sh ? `${sh.code}${sh.name ? ' · ' + sh.name : ''}` : (ent.customLabel || 'กะกำหนดเอง');
  };
  const branchSel = document.getElementById('scrBranchSel');
  if (branchSel) {
    branchSel.addEventListener('change', () => {
      const empSel = document.getElementById('scrEmpSel');
      const shSel = document.getElementById('scrNewShift');
      if (empSel) empSel.innerHTML = empOptions(branchSel.value);
      if (shSel) shSel.innerHTML = shiftOptions(branchSel.value);
      updOld();
    });
  }
  document.getElementById('scrEmpSel')?.addEventListener('change', updOld);
  document.getElementById('scrDate')?.addEventListener('input', updOld);

  $('#scrReqSubmit').addEventListener('click', async () => {
    const form = $('#scrReqForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    const fd = new FormData(form);
    const branchId = (fd.get('branchId') || '').toString().trim();
    const employeeId = (fd.get('employeeId') || '').toString().trim();
    const workDate = (fd.get('workDate') || '').toString().trim();
    const newShiftId = (fd.get('newShiftId') || '').toString().trim();
    const reason = (fd.get('reason') || '').toString().trim();
    const emp = DB.getEmployee(employeeId) || {};
    const employeeName = `${emp.firstName || ''} ${emp.lastName || ''}`.trim();
    const positionTitle = emp.positionTitle || '';
    const btn = $('#scrReqSubmit'); btn.disabled = true; btn.textContent = 'กำลังส่ง...';
    try {
      await DB.createShiftChangeRequest({ branchId, employeeId, employeeName, positionTitle, workDate, newShiftId, reason });
      modal.close();
      toast('✓ ส่งคำขอเปลี่ยนกะแล้ว — รอ AM/HR อนุมัติ', 'success');
      router.go('shift-changes');
    } catch (ex) {
      toast(ex.message || String(ex), 'error');
      btn.disabled = false; btn.textContent = 'ส่งคำขอ';
    }
  });
}

async function reviewShiftChangeUI(requestId, decision) {
  const action = decision === 'approve' ? 'อนุมัติ' : 'ปฏิเสธ';
  const msg = decision === 'approve'
    ? 'ยืนยันอนุมัติ — ระบบจะแก้กะในตารางงานให้อัตโนมัติ · หมายเหตุ (ทางเลือก):'
    : 'เหตุผลที่ปฏิเสธ (ทางเลือก):';
  const note = await modal.prompt(`${action}คำขอเปลี่ยนกะ`, msg, '');
  if (note === null) return;
  try {
    await DB.reviewShiftChangeRequest(requestId, decision, note);
    toast(decision === 'approve' ? '✓ อนุมัติแล้ว — แก้กะในตารางเรียบร้อย' : '✓ ปฏิเสธคำขอแล้ว', 'success');
    router.go('shift-changes');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

async function cancelShiftChangeUI(requestId) {
  const reason = await modal.prompt('ยกเลิกคำขอเปลี่ยนกะ', 'เหตุผลที่ยกเลิก (ทางเลือก):', '');
  if (reason === null) return;
  try {
    await DB.cancelShiftChangeRequest(requestId, reason);
    toast('ยกเลิกคำขอแล้ว', 'success');
    router.go('shift-changes');
  } catch (ex) {
    toast(ex.message || String(ex), 'error');
  }
}

function updateShiftChangeBadge() {
  const badge = document.getElementById('navBadgeShiftChange');
  if (!badge) return;
  const list = DB.data.shiftChangeRequests || [];
  let pending = 0;
  if (DB.isHR) {
    pending = list.filter(r => r.status === 'pending').length;
  } else if (DB.role === 'area_manager' || DB.role === 'operation_manager') {
    const managed = DB._managedBranches || [];
    pending = list.filter(r => r.status === 'pending' && managed.includes(r.branchId)).length;
  }
  if (pending > 0) {
    badge.textContent = String(pending);
    badge.style.display = 'inline-block';
    badge.title = `${pending} คำขอเปลี่ยนกะรออนุมัติ`;
  } else {
    badge.style.display = 'none';
  }
}

// ═══════════════════════════════════════════════════════════════════
// TIME ATTENDANCE — บันทึกเวลาสแกนนิ้ว เข้า-ออกงาน (นำเข้าจากเครื่องสแกน)
//   รองรับหลายเครื่อง/หลายฟอร์แมต ผ่าน auto-detect + map คอลัมน์เอง
//   raw-punch (1 แถว=1 ครั้ง → จับคู่ให้เอง) | paired (1 แถว=1 วัน)
// ═══════════════════════════════════════════════════════════════════
const _attState = (() => {
  const d = new Date();
  return { year: d.getFullYear(), month: d.getMonth() + 1, branch: '', status: '', loaded: false, loading: false };
})();

const ATT_ANOMALY = {
  missing_in:   { label: 'ลืมสแกนเข้า',     cls: 'badge-danger'  },
  missing_out:  { label: 'ลืมสแกนออก',     cls: 'badge-danger'  },
  no_punch:     { label: 'ไม่มีข้อมูล',      cls: 'badge-danger'  },
  check_break:  { label: 'พักไม่ครบคู่',     cls: 'badge-warning' },
  many_punches: { label: 'สแกนเกิน 4 ครั้ง', cls: 'badge-warning' }
};

const _TH_MONTHS = ['ม.ค.','ก.พ.','มี.ค.','เม.ย.','พ.ค.','มิ.ย.','ก.ค.','ส.ค.','ก.ย.','ต.ค.','พ.ย.','ธ.ค.'];

function _attMonthRange(y, m) {
  return {
    from: new Date(y, m - 1, 1).toLocaleDateString('en-CA'),
    to: new Date(y, m, 0).toLocaleDateString('en-CA')
  };
}
function _attFmtMinutes(min) {
  if (min == null) return '-';
  const h = Math.floor(min / 60), m = min % 60;
  return (h ? `${h} ชม. ` : '') + `${m} น.`;
}
function _attHM(t) { return t ? String(t).slice(0, 5) : '—'; }

// ─── PARSE date/time จากเซลล์ (รองรับหลายรูปแบบ + Excel Date object) ───
function _attYmd(y, mo, d) {
  if (y > 2400) y -= 543;                 // พ.ศ. → ค.ศ.
  if (mo < 1 || mo > 12 || d < 1 || d > 31) return null;
  return `${y}-${String(mo).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
}
function attParseDate(v) {
  if (v == null || v === '') return null;
  if (v instanceof Date) {
    // Excel time-only cell = ปี 1899/1900 → ไม่ใช่วันที่จริง
    if (v.getFullYear() < 1970) return null;
    return v.toLocaleDateString('en-CA');
  }
  let s = String(v).trim();
  if (!s) return null;
  // ── เลขล้วนไม่มีตัวคั่น (CSV→number ทำ 0 นำหน้าหาย) เช่น 01052569→1052569, 01052026→1052026 ──
  if (/^\d+$/.test(s)) {
    let g = s;
    if (g.length === 7) g = '0' + g;                 // วันหลักเดียว 0 หาย → pad
    if (g.length === 8) {
      const first4 = +g.slice(0, 4);
      // YYYYMMDD ถ้า 4 ตัวแรกเป็นปี (ค.ศ. 1970-2100 หรือ พ.ศ. 2470-2643)
      if ((first4 >= 1970 && first4 <= 2100) || (first4 >= 2470 && first4 <= 2643)) {
        const r = _attYmd(first4, +g.slice(4, 6), +g.slice(6, 8));
        if (r) return r;
      }
      let d = +g.slice(0, 2), mo = +g.slice(2, 4), y = +g.slice(4, 8);  // DDMMYYYY
      if (mo > 12 && d <= 12) { const t = d; d = mo; mo = t; }
      const r = _attYmd(y, mo, d);
      if (r) return r;
    }
    if (g.length === 6) {                            // DDMMYY (เดา ค.ศ. 20xx)
      let d = +g.slice(0, 2), mo = +g.slice(2, 4), y = 2000 + (+g.slice(4, 6));
      if (mo > 12 && d <= 12) { const t = d; d = mo; mo = t; }
      const r = _attYmd(y, mo, d);
      if (r) return r;
    }
    return null;
  }
  // ── มีตัวคั่น ──
  let m = s.match(/(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})/);   // YYYY-MM-DD
  if (m) return _attYmd(+m[1], +m[2], +m[3]);
  m = s.match(/(\d{1,2})[-/.](\d{1,2})[-/.](\d{2,4})/);     // DD/MM/YYYY
  if (m) {
    let d = +m[1], mo = +m[2], y = +m[3];
    if (y < 100) y += 2000;
    if (mo > 12 && d <= 12) { const t = d; d = mo; mo = t; }  // เผื่อ MM/DD
    return _attYmd(y, mo, d);
  }
  return null;
}
function attParseTime(v) {
  if (v == null || v === '') return null;
  if (v instanceof Date) {
    return `${String(v.getHours()).padStart(2,'0')}:${String(v.getMinutes()).padStart(2,'0')}`;
  }
  const s = String(v).trim();
  if (!s) return null;
  // Excel time = เศษส่วนของวัน (0..1)
  if (/^0?\.\d+$/.test(s)) {
    const total = Math.round(Number(s) * 24 * 60);
    return `${String(Math.floor(total / 60) % 24).padStart(2,'0')}:${String(total % 60).padStart(2,'0')}`;
  }
  // ── เลขล้วน HHMMSS / HHMM (CSV→number ทำ 0 นำหน้าหาย) เช่น 085833→85833, 0800→800 ──
  if (/^\d+$/.test(s)) {
    let d = s;
    if (d.length === 5) d = '0' + d;        // HMMSS → HHMMSS
    else if (d.length === 3) d = '0' + d;   // HMM → HHMM
    let h, mi;
    if (d.length === 6 || d.length === 4) { h = +d.slice(0, 2); mi = +d.slice(2, 4); }
    else if (d.length <= 2) { h = +d; mi = 0; }
    else return null;
    if (h > 23 || mi > 59) return null;
    return `${String(h).padStart(2,'0')}:${String(mi).padStart(2,'0')}`;
  }
  // ── มี ':' (+ AM/PM) ──
  const ap = s.match(/(AM|PM)/i);
  const m = s.match(/(\d{1,2}):(\d{2})(?::\d{2})?/);
  if (!m) return null;
  let h = +m[1]; const mi = +m[2];
  if (ap) { const u = ap[1].toUpperCase(); if (u === 'PM' && h < 12) h += 12; if (u === 'AM' && h === 12) h = 0; }
  if (h > 23 || mi > 59) return null;
  return `${String(h).padStart(2,'0')}:${String(mi).padStart(2,'0')}`;
}

const _attToMin = (t) => { if (!t) return null; const p = String(t).split(':'); return (+p[0]) * 60 + (+p[1]); };

// dedup ครั้งสแกนที่ห่างกัน < 2 นาที (เครื่องมักสแกนซ้ำ) + เรียงเวลา
function attDedupTimes(times) {
  const sorted = times.filter(Boolean).slice().sort((a, b) => _attToMin(a) - _attToMin(b));
  const out = [];
  for (const t of sorted) {
    if (!out.length || Math.abs(_attToMin(t) - _attToMin(out[out.length - 1])) >= 2) out.push(t);
  }
  return out;
}
// จับคู่ครั้งสแกน (เรียงแล้ว) → เข้า/พักออก/พักเข้า/ออก
function attAssignPunches(times) {
  const n = times.length;
  const r = { checkIn: null, breakOut: null, breakIn: null, checkOut: null };
  if (n === 0) return r;
  if (n === 1) { r.checkIn = times[0]; return r; }              // ลืมสแกนออก
  r.checkIn = times[0]; r.checkOut = times[n - 1];
  if (n === 2) return r;                                        // เข้า-ออก (ไม่มีพัก)
  if (n === 3) { r.breakOut = times[1]; return r; }            // พักไม่ครบคู่
  r.breakOut = times[1]; r.breakIn = times[n - 2];             // n>=4: ใช้ตัวที่ 2 และรองสุดท้าย
  return r;
}
function attCalcWorkMin(rec) {
  const ci = _attToMin(rec.checkIn), co = _attToMin(rec.checkOut);
  const bo = _attToMin(rec.breakOut), bi = _attToMin(rec.breakIn);
  let brk = 0;
  if (bo != null && bi != null) { brk = bi - bo; if (brk < 0) brk += 1440; if (brk < 0) brk = 0; }
  if (ci == null || co == null) return null;
  let w = co - ci; if (w < 0) w += 1440; w -= brk;
  return w < 0 ? 0 : w;
}

// ─── จับคู่รหัสสแกน → พนักงานในระบบ (ลอง exact ก่อน แล้วตัด 0 นำหน้า) ───
function attBuildEmpLookup() {
  const byId = new Map(), byNum = new Map();
  for (const e of DB.getEmployees()) {
    const id = String(e.id).trim();
    byId.set(id, e);
    const num = id.replace(/^0+/, '');
    if (num && !byNum.has(num)) byNum.set(num, e);
  }
  return { byId, byNum };
}
function attMatchEmp(lk, rawId) {
  const id = String(rawId == null ? '' : rawId).trim();
  if (!id) return null;
  if (lk.byId.has(id)) return lk.byId.get(id);
  const num = id.replace(/^0+/, '');
  if (num && lk.byNum.has(num)) return lk.byNum.get(num);
  return null;
}

// ─── auto-detect คอลัมน์จากชื่อหัวตาราง ───
const _ATT_ALIASES = {
  empId:    ['staffcode','staffid','staffno','employeecode','empcode','รหัสพนักงาน','รหัสผู้ใช้','employeeid','employeeno','userid','enrollno','enrollnumber','badgenumber','acno','รหัสบัตร','empid','staff','pin','รหัส'],
  date:     ['วันทำงาน','วันที่ทำงาน','workingdate','workdate','attdate','วันที่','date','วัน'],
  time:     ['เวลาสแกน','atttime','clocktime','เวลา','time'],
  datetime: ['วันที่เวลา','วันเวลา','datetime','timestamp','scantime','punchtime','recordtime','transactiontime','date/time'],
  checkIn:  ['เวลาเข้า','เข้างาน','clockin','checkin','timein','onduty','เข้า'],
  breakOut: ['พักออก','ออกพัก','breakout','breakstart'],
  breakIn:  ['พักเข้า','เข้าพัก','breakin','breakend','กลับพัก'],
  checkOut: ['เวลาออก','ออกงาน','clockout','checkout','timeout','offduty','ออก']
};
function attDetectCol(headers, key) {
  const norm = (s) => String(s).toLowerCase().replace(/[\s_\-./()]/g, '');
  const H = headers.map(h => ({ raw: h, n: norm(h) }));
  const aliases = _ATT_ALIASES[key] || [];
  for (const a of aliases) {                       // exact normalized
    const an = norm(a);
    const hit = H.find(h => h.n === an);
    if (hit) return hit.raw;
  }
  for (const a of aliases) {                       // substring (เฉพาะ alias ยาว ≥4 กัน false match)
    const an = norm(a);
    if (an.length < 4) continue;
    const hit = H.find(h => h.n.includes(an));
    if (hit) return hit.raw;
  }
  return '';
}
// ตรวจหาคอลัมน์ที่เก็บ "เวลาสแกน" (ได้หลายช่อง) — เรียงลำดับ
//   1) คอลัมน์เลขลำดับ: เวลา 1/2/3/4, time1..4  → 2) TimeIn/TimeOut  → 3) เวลาเดี่ยว
function attDetectTimeCols(headers) {
  const norm = (s) => String(s).toLowerCase().replace(/[\s_\-./()]/g, '');
  const numbered = [];
  for (const h of headers) {
    const m = norm(h).match(/^(?:เวลา|time|punch|scan|ครั้งที่|ครั้ง)([1-9])$/);
    if (m) numbered.push({ h, idx: +m[1] });
  }
  if (numbered.length) {
    numbered.sort((a, b) => a.idx - b.idx);
    return numbered.map(x => x.h).slice(0, 4);
  }
  const cols = [];
  const ci = attDetectCol(headers, 'checkIn');
  const co = attDetectCol(headers, 'checkOut');
  if (ci) cols.push(ci);
  if (co && co !== ci) cols.push(co);
  if (cols.length) return cols;
  const t = attDetectCol(headers, 'time');
  if (t) cols.push(t);
  return cols;
}

// ─── โหลดเดือนที่เลือก แล้ว re-render ───
async function attLoadAndRender() {
  if (_attState.loading) return;
  _attState.loading = true;
  const { from, to } = _attMonthRange(_attState.year, _attState.month);
  try {
    await DB.loadTimeAttendance({ from, to, branch: _attState.branch || null });
    _attState.loaded = true;
  } catch (ex) {
    toast('โหลดข้อมูลเวลาไม่สำเร็จ: ' + (ex.message || ex), 'error');
  } finally {
    _attState.loading = false;
  }
  if (router.current === 'attendance') router.go('attendance');
}
function setAttMonth(val) {
  const [y, m] = String(val).split('-').map(Number);
  if (y && m) { _attState.year = y; _attState.month = m; _attState.loaded = false; attLoadAndRender(); }
}
function setAttBranch(v) { _attState.branch = v || ''; _attState.loaded = false; attLoadAndRender(); }
function setAttStatus(v) { _attState.status = v || ''; if (router.current === 'attendance') router.go('attendance'); }
function clearAttFilter() { _attState.branch = ''; _attState.status = ''; _attState.loaded = false; attLoadAndRender(); }

function attMonthOptionsHtml() {
  const now = new Date();
  let out = '';
  for (let i = 0; i < 18; i++) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    const y = d.getFullYear(), m = d.getMonth() + 1;
    const sel = (y === _attState.year && m === _attState.month) ? 'selected' : '';
    out += `<option value="${y}-${String(m).padStart(2,'0')}" ${sel}>${_TH_MONTHS[m-1]} ${y + 543}</option>`;
  }
  return out;
}
function attBranchOptionsHtml() {
  const branches = (DB.getBranchMaster ? DB.getBranchMaster({ activeOnly: true }) : []) || [];
  return '<option value="">— ทุกสาขา —</option>' + branches.map(b =>
    `<option value="${escapeHtml(b.id)}" ${_attState.branch === b.id ? 'selected' : ''}>${escapeHtml(b.id)}${b.name ? ' · ' + escapeHtml(b.name) : ''}</option>`).join('');
}
function _attStatusCell(r) {
  if (r.anomaly && ATT_ANOMALY[r.anomaly]) {
    const a = ATT_ANOMALY[r.anomaly];
    return `<span class="badge ${a.cls}" style="font-size:11px">${a.label}</span>`;
  }
  if (r.isComplete) return `<span class="badge badge-success" style="font-size:11px">ครบ</span>`;
  return `<span class="badge" style="font-size:11px">—</span>`;
}

